INSERT INTO `documents_translations` VALUES (1,1,'en','Basic BIM','<h1 class=\"hh6\">Tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB</h1>\r\n<p class=\"link\"><a href=\"https://thuthuat.taimienphi.vn/canews_he-thong-may-tinh-35.aspx\">Hệ thống m&aacute;y t&iacute;nh</a>&nbsp;&raquo;&nbsp;<a class=\"acN\" href=\"https://thuthuat.taimienphi.vn/canews_ghost-cai-windows-68.aspx\">Ghost, c&agrave;i windows</a></p>\r\n<div class=\"cl\">&nbsp;</div>\r\n<div class=\"des3 clearfix\">\r\n<div class=\"shortdes clearfix\"><strong>Tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB, bạn đ&atilde; thử chưa? Với sự ph&aacute;t triển của c&ocirc;ng nghệ hiện nay, người d&ugrave;ng c&oacute; thể setup nhiều bộ c&agrave;i hệ điều h&agrave;nh tr&ecirc;n một chiếc USB m&agrave; kh&ocirc;ng phải 1 bộ c&agrave;i như trước. B&agrave;i viết dưới đ&acirc;y, Taimienphi sẽ hướng dẫn c&aacute;c bạn tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB cực kỳ đơn giản.</strong></div>\r\n<div id=\"cph1_newsrel\">\r\n<p class=\"tit9 clearfix\">B&agrave;i viết li&ecirc;n quan</p>\r\n<div>\r\n<div class=\"newsrel\">\r\n<ul class=\"ulf1 clearfix\">\r\n<li><a href=\"https://thuthuat.taimienphi.vn/cai-windows-7-usbdvd-download-tool-12549n.aspx\">Hướng dẫn c&agrave;i Windows 7 USB/DVD Download Tool, hỗ trợ tạo usb boots</a></li>\r\n<li><a href=\"https://thuthuat.taimienphi.vn/phan-mem-tao-boot-cai-win-7-bang-usb-15767n.aspx\">Top 10 phần mềm tạo boot c&agrave;i Win 7 bằng USB</a></li>\r\n<li><a href=\"https://thuthuat.taimienphi.vn/tao-bo-cai-windows-81-tu-usb-3640n.aspx\">C&aacute;ch tạo bộ c&agrave;i Windows 8.1 từ USB</a></li>\r\n<li><a href=\"https://thuthuat.taimienphi.vn/cach-tao-usb-cai-windows-bang-windows-7-usb-download-tool-32619n.aspx\">C&aacute;ch tạo USB c&agrave;i Windows bằng Windows 7 USB Download Tool</a></li>\r\n<li><a href=\"https://thuthuat.taimienphi.vn/tao-bo-cai-windows-10-tu-usb-3641n.aspx\">C&aacute;ch tạo bộ c&agrave;i Windows 10 từ USB, tạo USB Boot Win 10</a></li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div id=\"cph1_gatop\" class=\"gabody1\">\r\n<div align=\"center\">&nbsp;</div>\r\n</div>\r\n<div id=\"startrel\" class=\"cl\">&nbsp;</div>\r\n<div id=\"relshow\">&nbsp;</div>\r\n<p>Tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB l&agrave; phương ph&aacute;p gi&uacute;p bạn tiết kiệm thời gian nhất trong việc tạo c&aacute;c bộ c&agrave;i Windows sử dụng nhiều mục đ&iacute;ch thay v&igrave; tạo ri&ecirc;ng lẻ bộ c&agrave;i. Trước đ&acirc;y ch&uacute;ng ta thường&nbsp;<a href=\"https://thuthuat.taimienphi.vn/cai-windows-7-bang-usb-607n.aspx\">c&agrave;i win 7 bằng usb</a>, nhưng tất nhi&ecirc;n l&agrave; chỉ được ph&eacute;p c&agrave;i ri&ecirc;ng win7. Nếu bạn muốn c&agrave;i win 10 bằng usb bạn phải x&oacute;a win 7 đi.</p>\r\n<p><img src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-1.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"314\" /></p>\r\n<p>Nhưng như đ&atilde; n&oacute;i ở tr&ecirc;n, phần mềm m&agrave; Taimienphi.vn muốn đề cập đến sẽ gi&uacute;p bạn tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB một c&aacute;ch dễ d&agrave;ng v&agrave; hiệu quả nhất thay v&igrave; phải c&agrave;i ri&ecirc;ng lẻ win 7 hay&nbsp;<a href=\"https://thuthuat.taimienphi.vn/ghi-file-iso-windows-10-technical-preview-ra-usb-2584n.aspx\">c&agrave;i win 10</a>&nbsp;tr&ecirc;n USB như mọi khi.</p>\r\n<h2><strong><u>HƯ</u><u>Ớ</u><u>NG D</u><u>Ẫ</u><u>N T</u><u>Ạ</u><u>O B</u><u>Ộ</u><u>&nbsp;C&Agrave;I WINDOWS 10, 8.1, 7 TR&Ecirc;N C&Ugrave;NG USB.</u></strong></h2>\r\n<p>* Bạn cần chuẩn bị những c&ocirc;ng cụ sau để tạo bộ c&agrave;i Windows 10, 8.1,7<br />- Bộ c&agrave;i Windows 7: Download&nbsp;<a href=\"https://taimienphi.vn/download-windows-7-8538\" target=\"_blank\" rel=\"noopener\"><strong>Windows 7</strong></a>.<br />- Bộ c&agrave;i Windows 8: Download&nbsp;<a href=\"https://taimienphi.vn/download-windows-8-8536\" target=\"_blank\" rel=\"noopener\"><strong>Windows 8</strong></a>.<br />- Bộ c&agrave;i Windows 8.1: Download&nbsp;<strong><a href=\"https://taimienphi.vn/download-windows-81-8537\" target=\"_blank\" rel=\"noopener\">Windows 8.1</a>.</strong><br />- Bộ c&agrave;i Windows 10: Download&nbsp;<a href=\"https://taimienphi.vn/download-windows-10-12463\" target=\"_blank\" rel=\"noopener\"><strong>Windows 10</strong></a>.</p>\r\n<p><em>Bư</em><em>ớ</em><em>c 1:&nbsp;</em>Tải c&ocirc;ng cụ&nbsp;<strong><a href=\"https://taimienphi.vn/download-usb-hdd-boot-21768\" target=\"_blank\" rel=\"noopener\">USB HDD BOOT</a></strong>&nbsp;tại đ&acirc;y</p>\r\n<p><img src=\"http://i1.taimienphi.vn/tmp/cf/aut/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-2.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"288\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 2:&nbsp;</em>Sau khi ho&agrave;n t&aacute;t tải về, bạn mở phần mềm ra sẽ thấy c&oacute; 2 t&iacute;nh năng l&agrave; tạo menu boot cho m&aacute;y t&iacute;nh hoặc c&aacute;c thiết bị USB, bấm v&agrave;o&nbsp;<strong>T</strong><strong>ạ</strong><strong>o boot đa năng cho đĩa USB</strong>.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-4.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"425\" height=\"248\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-4.jpg\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 3:&nbsp;</em>Ngay sau bước n&agrave;y, 1 bảng th&ocirc;ng số hiện ra cho ph&eacute;p bạn t&ugrave;y chọn USB, định dạng cũng như t&iacute;ch hợp c&aacute;c phi&ecirc;n bản c&agrave;i. Bạn chỉ cần bấm v&agrave;o Định dạng&nbsp;<strong>FAT32&nbsp;</strong>hay&nbsp;<strong>NTFS&nbsp;</strong>v&agrave; sau đ&oacute; t&iacute;ch chọn&nbsp;<strong>T&iacute;ch h</strong><strong>ợ</strong><strong>p c&agrave;i đ</strong><strong>ặ</strong><strong>t WIndows t</strong><strong>ừ</strong><strong>&nbsp;file ISO v&agrave;o&nbsp;</strong><strong>ổ</strong><strong>&nbsp;đĩa&nbsp;</strong>v&agrave; lựa chọn c&aacute;c phi&ecirc;n bản muốn c&agrave;i đặt rồi sau đ&oacute; bấm v&agrave;o&nbsp;<strong>B</strong><strong>ắ</strong><strong>t Đ</strong><strong>ầ</strong><strong>u</strong>.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-5.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"395\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-5.jpg\" /></p>\r\n<p>- Một th&ocirc;ng b&aacute;o nữa hiện ra y&ecirc;u cầu bạn x&aacute;c nhận lại một lần nữa bằng tiếng Việt, nếu đ&acirc;y l&agrave; USB mới kh&ocirc;ng c&oacute; dữ liệu bạn cứ bấm&nbsp;<strong>OK</strong>.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-6.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"450\" height=\"274\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-6.jpg\" /></p>\r\n<p>- Qu&aacute; tr&igrave;nh chạy v&agrave; nạp phần mềm để tạo bộ c&agrave;i Windows 10, 8.1, 7 sẽ mất khoảng 1 ph&uacute;t.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-7.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"108\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-7.jpg\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 4:&nbsp;</em>Tiếp theo bạn tải bộ c&agrave;i&nbsp;<a href=\"https://taimienphi.vn/download-creat-wim-files-32766\" target=\"_blank\" rel=\"noopener\"><strong>Creat Wim Files</strong></a>&nbsp;tại đ&acirc;y sau đ&oacute;giải n&eacute;n ra.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-8.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"493\" height=\"229\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-8.jpg\" /></p>\r\n<p>- Trong bộ c&agrave;i WIM FILES chia ra rất nhiều c&aacute;c phi&ecirc;n bản, nếu bạn muốn c&agrave;i Windows 10 v&agrave;o trong USB h&atilde;y mở bộ c&agrave;i đ&oacute; ra, c&aacute;ch tr&ecirc;n gi&uacute;p bạn đưa bộ c&agrave;i windows v&agrave;o trong USB sau khi đ&atilde; sử dụng USBHDDBOOT để tạo file boot.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-9.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"400\" height=\"411\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-9.jpg\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 5:&nbsp;</em>Như ti&ecirc;u đề b&agrave;i viết, ch&uacute;ng ta sẽ đưa Windows 10, 8.1 v&agrave; 7 v&agrave;o, trong v&iacute; dụ sau đ&acirc;y Taimienphi.vn xin l&agrave;m mẫu việc đưa&nbsp;<strong>Windows 10 64bit&nbsp;</strong>v&agrave;o, lưu &yacute; l&agrave; ch&uacute;ng ta c&oacute; thể lặp lại thao t&aacute;c n&agrave;y bao nhi&ecirc;u lần cũng được. Miễn sao lựa chọn bộ c&agrave;i đ&uacute;ng với phi&ecirc;n bản Windows l&agrave; được. Sau khi mở bộ c&agrave;i hỗ trợ USB HDD BOOT gi&agrave;nh cho phi&ecirc;n bản Windows 10 64bit, bạn ấn v&agrave;o T&igrave;m đến để lựa chọn file Windows 10 64bit đ&atilde; tải về m&aacute;y.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-10.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"231\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-10.jpg\" /></p>\r\n<p>- Lựa chọn ch&iacute;nh x&aacute;c phi&ecirc;n bản Windows 10 64bit rồi&nbsp;<strong>Open</strong>.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-11.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"305\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-11.jpg\" /></p>\r\n<p>- Sau khi lựa chọn ho&agrave;n tất, bầm v&agrave;o&nbsp;<strong>Bắt đầu</strong>&nbsp;để tiến h&agrave;nh sao ch&eacute;p.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-12.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"231\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-12.jpg\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 6:&nbsp;</em>Đợi một l&aacute;t, t&ugrave;y v&agrave;o dung lượng file v&agrave; khi c&oacute; th&ocirc;ng b&aacute;o như h&igrave;nh dưới l&agrave; bạn đ&atilde; c&agrave;i đặt Windows 10 phi&ecirc;n bản 64bit th&agrave;nh c&ocirc;ng.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-13.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"231\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-13.jpg\" /></p>\r\n<p>Bạn cũng c&oacute; thể lặp lại c&aacute;c bước tr&ecirc;n v&agrave; c&agrave;i đặt cho Windows 7, Windows 8. Khi mở lại m&aacute;y t&iacute;nh, bạn v&agrave;o chế dộ BOOT như th&ocirc;ng thường sẽ thấy sự kh&aacute;c biệt.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-14.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"281\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-14.jpg\" /></p>\r\n<p>Giao diện thực tế b&ecirc;n trong</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-15.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"281\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-15.jpg\" /></p>\r\n<p>https://thuthuat.taimienphi.vn/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-22138n.aspx<br />Tr&ecirc;n đ&acirc;y Taimienphi.vn đ&atilde; hướng dẫn xong c&aacute;c bạn c&aacute;ch tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB. Gi&uacute;p bạn tạo được một bộ c&agrave;i đa năng gi&uacute;p &iacute;ch cho c&ocirc;ng việc c&agrave;i đặt m&aacute;y số lượng lớn. Ngo&agrave;i ra đ&acirc;y cũng l&agrave; một phần mềm t&iacute;ch hợp Boot với nhiều c&ocirc;ng cụ hữu &iacute;ch gi&uacute;p cho c&ocirc;ng việc của bạn. Thay v&igrave; bạn phải sử dụng c&aacute;c phần mềm&nbsp;<a href=\"https://thuthuat.taimienphi.vn/tao-usb-boot-voi-hirens-boot-954n.aspx\">tạo Boot</a>&nbsp;c&agrave;i Win bằng USB. Cũng giống như top c&aacute;c phần mềm&nbsp;<strong><a href=\"https://thuthuat.taimienphi.vn/phan-mem-tao-boot-cai-win-7-bang-usb-15767n.aspx\">tạo Boot c&agrave;i Win 7 bằng USB</a></strong>&nbsp;m&agrave; Taimienphi.vn đ&atilde; giới thiệu ở b&agrave;i viết trước.</p>\r\n</div>','Thẻ Meta Title [en]','Cannonical Link [en]','https://thuthuat.taimienphi.vn/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-22138n.aspx','Thẻ Meta Keyword [en]',NULL),(2,1,'vi','Danh mục bài viết 2','<h1 class=\"hh6\">Tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB</h1>\r\n<p class=\"link\"><a href=\"https://thuthuat.taimienphi.vn/canews_he-thong-may-tinh-35.aspx\">Hệ thống m&aacute;y t&iacute;nh</a>&nbsp;&raquo;&nbsp;<a class=\"acN\" href=\"https://thuthuat.taimienphi.vn/canews_ghost-cai-windows-68.aspx\">Ghost, c&agrave;i windows</a></p>\r\n<div class=\"cl\">&nbsp;</div>\r\n<div class=\"des3 clearfix\">\r\n<div class=\"shortdes clearfix\"><strong>Tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB, bạn đ&atilde; thử chưa? Với sự ph&aacute;t triển của c&ocirc;ng nghệ hiện nay, người d&ugrave;ng c&oacute; thể setup nhiều bộ c&agrave;i hệ điều h&agrave;nh tr&ecirc;n một chiếc USB m&agrave; kh&ocirc;ng phải 1 bộ c&agrave;i như trước. B&agrave;i viết dưới đ&acirc;y, Taimienphi sẽ hướng dẫn c&aacute;c bạn tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB cực kỳ đơn giản.</strong></div>\r\n<div id=\"cph1_newsrel\">\r\n<p class=\"tit9 clearfix\">B&agrave;i viết li&ecirc;n quan</p>\r\n<div>\r\n<div class=\"newsrel\">\r\n<ul class=\"ulf1 clearfix\">\r\n<li><a href=\"https://thuthuat.taimienphi.vn/cai-windows-7-usbdvd-download-tool-12549n.aspx\">Hướng dẫn c&agrave;i Windows 7 USB/DVD Download Tool, hỗ trợ tạo usb boots</a></li>\r\n<li><a href=\"https://thuthuat.taimienphi.vn/phan-mem-tao-boot-cai-win-7-bang-usb-15767n.aspx\">Top 10 phần mềm tạo boot c&agrave;i Win 7 bằng USB</a></li>\r\n<li><a href=\"https://thuthuat.taimienphi.vn/tao-bo-cai-windows-81-tu-usb-3640n.aspx\">C&aacute;ch tạo bộ c&agrave;i Windows 8.1 từ USB</a></li>\r\n<li><a href=\"https://thuthuat.taimienphi.vn/cach-tao-usb-cai-windows-bang-windows-7-usb-download-tool-32619n.aspx\">C&aacute;ch tạo USB c&agrave;i Windows bằng Windows 7 USB Download Tool</a></li>\r\n<li><a href=\"https://thuthuat.taimienphi.vn/tao-bo-cai-windows-10-tu-usb-3641n.aspx\">C&aacute;ch tạo bộ c&agrave;i Windows 10 từ USB, tạo USB Boot Win 10</a></li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div id=\"cph1_gatop\" class=\"gabody1\">\r\n<div align=\"center\">&nbsp;</div>\r\n</div>\r\n<div id=\"startrel\" class=\"cl\">&nbsp;</div>\r\n<div id=\"relshow\">&nbsp;</div>\r\n<p>Tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB l&agrave; phương ph&aacute;p gi&uacute;p bạn tiết kiệm thời gian nhất trong việc tạo c&aacute;c bộ c&agrave;i Windows sử dụng nhiều mục đ&iacute;ch thay v&igrave; tạo ri&ecirc;ng lẻ bộ c&agrave;i. Trước đ&acirc;y ch&uacute;ng ta thường&nbsp;<a href=\"https://thuthuat.taimienphi.vn/cai-windows-7-bang-usb-607n.aspx\">c&agrave;i win 7 bằng usb</a>, nhưng tất nhi&ecirc;n l&agrave; chỉ được ph&eacute;p c&agrave;i ri&ecirc;ng win7. Nếu bạn muốn c&agrave;i win 10 bằng usb bạn phải x&oacute;a win 7 đi.</p>\r\n<p><img src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-1.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"314\" /></p>\r\n<p>Nhưng như đ&atilde; n&oacute;i ở tr&ecirc;n, phần mềm m&agrave; Taimienphi.vn muốn đề cập đến sẽ gi&uacute;p bạn tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB một c&aacute;ch dễ d&agrave;ng v&agrave; hiệu quả nhất thay v&igrave; phải c&agrave;i ri&ecirc;ng lẻ win 7 hay&nbsp;<a href=\"https://thuthuat.taimienphi.vn/ghi-file-iso-windows-10-technical-preview-ra-usb-2584n.aspx\">c&agrave;i win 10</a>&nbsp;tr&ecirc;n USB như mọi khi.</p>\r\n<h2><strong><u>HƯ</u><u>Ớ</u><u>NG D</u><u>Ẫ</u><u>N T</u><u>Ạ</u><u>O B</u><u>Ộ</u><u>&nbsp;C&Agrave;I WINDOWS 10, 8.1, 7 TR&Ecirc;N C&Ugrave;NG USB.</u></strong></h2>\r\n<p>* Bạn cần chuẩn bị những c&ocirc;ng cụ sau để tạo bộ c&agrave;i Windows 10, 8.1,7<br />- Bộ c&agrave;i Windows 7: Download&nbsp;<a href=\"https://taimienphi.vn/download-windows-7-8538\" target=\"_blank\" rel=\"noopener\"><strong>Windows 7</strong></a>.<br />- Bộ c&agrave;i Windows 8: Download&nbsp;<a href=\"https://taimienphi.vn/download-windows-8-8536\" target=\"_blank\" rel=\"noopener\"><strong>Windows 8</strong></a>.<br />- Bộ c&agrave;i Windows 8.1: Download&nbsp;<strong><a href=\"https://taimienphi.vn/download-windows-81-8537\" target=\"_blank\" rel=\"noopener\">Windows 8.1</a>.</strong><br />- Bộ c&agrave;i Windows 10: Download&nbsp;<a href=\"https://taimienphi.vn/download-windows-10-12463\" target=\"_blank\" rel=\"noopener\"><strong>Windows 10</strong></a>.</p>\r\n<p><em>Bư</em><em>ớ</em><em>c 1:&nbsp;</em>Tải c&ocirc;ng cụ&nbsp;<strong><a href=\"https://taimienphi.vn/download-usb-hdd-boot-21768\" target=\"_blank\" rel=\"noopener\">USB HDD BOOT</a></strong>&nbsp;tại đ&acirc;y</p>\r\n<p><img src=\"http://i1.taimienphi.vn/tmp/cf/aut/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-2.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"288\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 2:&nbsp;</em>Sau khi ho&agrave;n t&aacute;t tải về, bạn mở phần mềm ra sẽ thấy c&oacute; 2 t&iacute;nh năng l&agrave; tạo menu boot cho m&aacute;y t&iacute;nh hoặc c&aacute;c thiết bị USB, bấm v&agrave;o&nbsp;<strong>T</strong><strong>ạ</strong><strong>o boot đa năng cho đĩa USB</strong>.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-4.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"425\" height=\"248\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-4.jpg\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 3:&nbsp;</em>Ngay sau bước n&agrave;y, 1 bảng th&ocirc;ng số hiện ra cho ph&eacute;p bạn t&ugrave;y chọn USB, định dạng cũng như t&iacute;ch hợp c&aacute;c phi&ecirc;n bản c&agrave;i. Bạn chỉ cần bấm v&agrave;o Định dạng&nbsp;<strong>FAT32&nbsp;</strong>hay&nbsp;<strong>NTFS&nbsp;</strong>v&agrave; sau đ&oacute; t&iacute;ch chọn&nbsp;<strong>T&iacute;ch h</strong><strong>ợ</strong><strong>p c&agrave;i đ</strong><strong>ặ</strong><strong>t WIndows t</strong><strong>ừ</strong><strong>&nbsp;file ISO v&agrave;o&nbsp;</strong><strong>ổ</strong><strong>&nbsp;đĩa&nbsp;</strong>v&agrave; lựa chọn c&aacute;c phi&ecirc;n bản muốn c&agrave;i đặt rồi sau đ&oacute; bấm v&agrave;o&nbsp;<strong>B</strong><strong>ắ</strong><strong>t Đ</strong><strong>ầ</strong><strong>u</strong>.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-5.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"395\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-5.jpg\" /></p>\r\n<p>- Một th&ocirc;ng b&aacute;o nữa hiện ra y&ecirc;u cầu bạn x&aacute;c nhận lại một lần nữa bằng tiếng Việt, nếu đ&acirc;y l&agrave; USB mới kh&ocirc;ng c&oacute; dữ liệu bạn cứ bấm&nbsp;<strong>OK</strong>.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-6.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"450\" height=\"274\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-6.jpg\" /></p>\r\n<p>- Qu&aacute; tr&igrave;nh chạy v&agrave; nạp phần mềm để tạo bộ c&agrave;i Windows 10, 8.1, 7 sẽ mất khoảng 1 ph&uacute;t.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-7.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"108\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-7.jpg\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 4:&nbsp;</em>Tiếp theo bạn tải bộ c&agrave;i&nbsp;<a href=\"https://taimienphi.vn/download-creat-wim-files-32766\" target=\"_blank\" rel=\"noopener\"><strong>Creat Wim Files</strong></a>&nbsp;tại đ&acirc;y sau đ&oacute;giải n&eacute;n ra.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-8.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"493\" height=\"229\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-8.jpg\" /></p>\r\n<p>- Trong bộ c&agrave;i WIM FILES chia ra rất nhiều c&aacute;c phi&ecirc;n bản, nếu bạn muốn c&agrave;i Windows 10 v&agrave;o trong USB h&atilde;y mở bộ c&agrave;i đ&oacute; ra, c&aacute;ch tr&ecirc;n gi&uacute;p bạn đưa bộ c&agrave;i windows v&agrave;o trong USB sau khi đ&atilde; sử dụng USBHDDBOOT để tạo file boot.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-9.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"400\" height=\"411\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-9.jpg\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 5:&nbsp;</em>Như ti&ecirc;u đề b&agrave;i viết, ch&uacute;ng ta sẽ đưa Windows 10, 8.1 v&agrave; 7 v&agrave;o, trong v&iacute; dụ sau đ&acirc;y Taimienphi.vn xin l&agrave;m mẫu việc đưa&nbsp;<strong>Windows 10 64bit&nbsp;</strong>v&agrave;o, lưu &yacute; l&agrave; ch&uacute;ng ta c&oacute; thể lặp lại thao t&aacute;c n&agrave;y bao nhi&ecirc;u lần cũng được. Miễn sao lựa chọn bộ c&agrave;i đ&uacute;ng với phi&ecirc;n bản Windows l&agrave; được. Sau khi mở bộ c&agrave;i hỗ trợ USB HDD BOOT gi&agrave;nh cho phi&ecirc;n bản Windows 10 64bit, bạn ấn v&agrave;o T&igrave;m đến để lựa chọn file Windows 10 64bit đ&atilde; tải về m&aacute;y.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-10.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"231\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-10.jpg\" /></p>\r\n<p>- Lựa chọn ch&iacute;nh x&aacute;c phi&ecirc;n bản Windows 10 64bit rồi&nbsp;<strong>Open</strong>.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-11.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"305\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-11.jpg\" /></p>\r\n<p>- Sau khi lựa chọn ho&agrave;n tất, bầm v&agrave;o&nbsp;<strong>Bắt đầu</strong>&nbsp;để tiến h&agrave;nh sao ch&eacute;p.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-12.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"231\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-12.jpg\" /></p>\r\n<p><em>Bư</em><em>ớ</em><em>c 6:&nbsp;</em>Đợi một l&aacute;t, t&ugrave;y v&agrave;o dung lượng file v&agrave; khi c&oacute; th&ocirc;ng b&aacute;o như h&igrave;nh dưới l&agrave; bạn đ&atilde; c&agrave;i đặt Windows 10 phi&ecirc;n bản 64bit th&agrave;nh c&ocirc;ng.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-13.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"231\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-13.jpg\" /></p>\r\n<p>Bạn cũng c&oacute; thể lặp lại c&aacute;c bước tr&ecirc;n v&agrave; c&agrave;i đặt cho Windows 7, Windows 8. Khi mở lại m&aacute;y t&iacute;nh, bạn v&agrave;o chế dộ BOOT như th&ocirc;ng thường sẽ thấy sự kh&aacute;c biệt.</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-14.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"281\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-14.jpg\" /></p>\r\n<p>Giao diện thực tế b&ecirc;n trong</p>\r\n<p><img class=\"lazy\" src=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-15.jpg\" alt=\"cai windows 10, 8.1, 7 tren cung usb\" width=\"500\" height=\"281\" data-original=\"https://imgt.taimienphi.vn/cf/Images/2017/3/vi/13/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-15.jpg\" /></p>\r\n<p>https://thuthuat.taimienphi.vn/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-22138n.aspx<br />Tr&ecirc;n đ&acirc;y Taimienphi.vn đ&atilde; hướng dẫn xong c&aacute;c bạn c&aacute;ch tạo bộ c&agrave;i Windows 10, 8.1, 7 tr&ecirc;n c&ugrave;ng USB. Gi&uacute;p bạn tạo được một bộ c&agrave;i đa năng gi&uacute;p &iacute;ch cho c&ocirc;ng việc c&agrave;i đặt m&aacute;y số lượng lớn. Ngo&agrave;i ra đ&acirc;y cũng l&agrave; một phần mềm t&iacute;ch hợp Boot với nhiều c&ocirc;ng cụ hữu &iacute;ch gi&uacute;p cho c&ocirc;ng việc của bạn. Thay v&igrave; bạn phải sử dụng c&aacute;c phần mềm&nbsp;<a href=\"https://thuthuat.taimienphi.vn/tao-usb-boot-voi-hirens-boot-954n.aspx\">tạo Boot</a>&nbsp;c&agrave;i Win bằng USB. Cũng giống như top c&aacute;c phần mềm&nbsp;<strong><a href=\"https://thuthuat.taimienphi.vn/phan-mem-tao-boot-cai-win-7-bang-usb-15767n.aspx\">tạo Boot c&agrave;i Win 7 bằng USB</a></strong>&nbsp;m&agrave; Taimienphi.vn đ&atilde; giới thiệu ở b&agrave;i viết trước.</p>\r\n</div>','Thẻ Meta Title [vi]','Cannonical Link [vi]','https://thuthuat.taimienphi.vn/tao-bo-cai-windows-10-8-1-7-tren-cung-usb-22138n.aspx','Thẻ Meta Keyword [vi]',NULL);
