INSERT INTO `product_categories` VALUES (1,'asdads',0,0,0,NULL,2,NULL,'2021-08-15 11:21:47','2021-08-15 11:22:01','2021-08-15 11:22:01'),(2,'pham-mem-bim-3d',0,1,1,'1629090005-pham-mem-bim-3d.png',2,2,'2021-08-15 21:56:38','2021-08-15 22:00:05',NULL),(3,'phan-mem-bim4d',2,0,0,'1629090018-phan-mem-bim4d.png',2,2,'2021-08-15 21:59:14','2021-08-16 00:01:45',NULL),(4,'phan-mem-bim-5d',1,1,1,'1629095819-phan-mem-bim-5d.png',2,NULL,'2021-08-15 23:36:59','2021-08-15 23:36:59',NULL),(5,'phan-mem-bim-6d',3,1,1,'1629095927-phan-mem-bim-6d.png',2,NULL,'2021-08-15 23:38:47','2021-08-15 23:38:47',NULL),(6,'bim-cho-dich-vu-an-uong',4,1,1,'1629096035-bim-cho-dich-vu-an-uong.png',2,NULL,'2021-08-15 23:40:35','2021-08-15 23:40:35',NULL);
