INSERT INTO `products_translations` VALUES (1,1,'en','Scan to BIM | Point Cloud to BIM services','We deliver accurate and parametric As-Built BIM Model and 2D CAD Model depicting the pipes, walls, slabs, roof planes, facades, and landscapes in and around the building. We provide models with LOD 100 to 500 to our clients covering all Architectural, Structural, MEPFP Elements along with Clash Detection for their Renovation, Refurbishment, Retrofit, or Reconstruction Projects.','<header class=\"vc_cta3-content-header sticky header-appear\">\r\n<h2 class=\"vc_custom_heading\">We Provide Scan to BIM Services from Point Cloud Data with Quality and Accuracy</h2>\r\n</header>\r\n<p>We understand the expectations of our customers very well. All we require is a&nbsp;<strong title=\"Point Cloud Scan\">Point Cloud Scan&nbsp;</strong>Laser Survey data and Company Standards ‐ template, drafting guidelines from our customers for us to deliver BIM model with required Revit Version: 2018/2019/2020/2021 and 2D as-built drawings with dimensions, annotations, and layering, etc.</p>\r\n<p>We provide data in four Levels of Documentation depending upon the requirement&mdash; Level 1 (Floor Plans), Level 2 (Exterior Elevation &amp; Roof Plans), Level 3 (Sections), and Level 4 (Site Layout Plans)</p>\r\n<p>Our&nbsp;<strong title=\"Scan to BIM Modeling\">Scan to BIM modeling</strong>&nbsp;team has experience of creating an information-rich as-built 3D BIM model or&nbsp;<strong title=\"2D Drawings\">2D drawings</strong>&nbsp;for the customers for design validation/planning/comparison, interference checks, MEP or construction elements demolition, or addition, documentation of existing building conditions, quantity take-off, and budget estimation.</p>\r\n<p>We provide our&nbsp;<strong title=\"Scan to BIM Services\">Scan to BIM services</strong>&nbsp;(aka Point Cloud Modeling services) to Laser Scanning Companies, Surveyors, Property Owners, Architectural Design Firms, MEP Engineering Companies, and General Contractors or Construction Management companies. Our experience includes developing parametric 3D BIM and 2D CAD models capturing architectural, structural, and MEP elements for hotel, educational, and commercial projects.</p>','<h2 class=\"text-extra-dark-gray margin-20px-bottom font-weight-600 display-inline-block alt-font heading-style2  heading-2\" data-fontsize=\"25px\" data-lineheight=\"35px\">Application of Scan to BIM</h2>\r\n<div class=\"last-paragraph-no-margin pofo-text-block-responsive-61199edccfa82\">\r\n<p>We understand what a well-executed plan takes for any&nbsp;<strong>Retrofit/Refurbishment</strong>,&nbsp;<strong>Reconstruction</strong>, and&nbsp;<strong>Renovation</strong>&nbsp;Project. All the data-driven decisions like planning, estimation, feasibility analysis, etc. depending on the accuracy of the as-built model which is created from a Point Cloud Scan. A point cloud is a set of points that accurately represents the building surfaces which are used to create a 3D BIM model or/and a 2D as-built drawing. We can work on both lasers surveyed data images and point cloud data. Our Scan to BIM services (Point Cloud Modeling services) also applies for&nbsp;<strong>Infrastructure&nbsp;</strong>projects like tunnels, bridges, roads, etc.</p>\r\n<p>We provide the following Level of Documentation for our clients:</p>\r\n<ul>\r\n<li><strong>Level 1: Floor Plans</strong></li>\r\n<li><strong>Level 2: Exterior Elevation &amp; Roof Plans</strong></li>\r\n<li><strong>Level 3: Sections</strong></li>\r\n<li><strong>Level 4: Site Layout Plans</strong></li>\r\n</ul>\r\n<p>We have experience of developing both&nbsp;<strong>Revit (.rvt) and CAD (.dwg)&nbsp;</strong>files from different formats of scans or point cloud data usually captured by commonly used laser scan machines&mdash; Leica Geosystems, Trimble, Faro Scanners, Reigl scanners. We also convert other format data (i.e. .fls, .e57, .pcg. .obj, .ptg) into Revit-ready format. We create information-rich BIM Ready 3D Model for Architectural, Structural and MEPFP Requirement, and Clash-free integration.</p>\r\n</div>','Scan to BIM | Point Cloud to BIM services','quet-sang-bim-dich-vu-point-cloud-toi-bim','We deliver accurate and parametric As-Built BIM Model and 2D CAD Model depicting the pipes, walls, slabs, roof planes, facades, and landscapes in and around the building. We provide models with LOD 100 to 500 to our clients covering all Architectural, Structural, MEPFP Elements along with Clash Detection for their Renovation, Refurbishment, Retrofit, or Reconstruction Projects.','BIM, Advance BIM',NULL),(2,1,'vi','Quét sang BIM | Dịch vụ Point Cloud tới BIM','Chúng tôi cung cấp Mô hình BIM được xây dựng theo thông số và chính xác và Mô hình CAD 2D mô tả các đường ống, tường, tấm, mặt phẳng mái, mặt tiền và cảnh quan trong và xung quanh tòa nhà. Chúng tôi cung cấp các mô hình có LOD 100 đến 500 cho khách hàng của mình bao gồm tất cả các Phần tử Kiến trúc, Kết cấu, MEPFP cùng với Phát hiện xung đột cho các Dự án Cải tạo, Tân trang, Trang bị thêm hoặc Tái thiết của họ.','<h1>Ch&uacute;ng t&ocirc;i cung cấp dịch vụ qu&eacute;t tới BIM từ dữ liệu đ&aacute;m m&acirc;y điểm với chất lượng v&agrave; độ ch&iacute;nh x&aacute;c</h1>\r\n<p>Ch&uacute;ng t&ocirc;i hiểu rất r&otilde; những mong đợi của kh&aacute;ch h&agrave;ng. Tất cả những g&igrave; ch&uacute;ng t&ocirc;i y&ecirc;u cầu l&agrave; dữ liệu Khảo s&aacute;t Laser Điểm Đ&aacute;m m&acirc;y v&agrave; Ti&ecirc;u chuẩn C&ocirc;ng ty - mẫu, soạn thảo hướng dẫn từ kh&aacute;ch h&agrave;ng của ch&uacute;ng t&ocirc;i để ch&uacute;ng t&ocirc;i cung cấp m&ocirc; h&igrave;nh BIM với Phi&ecirc;n bản Revit được y&ecirc;u cầu: 2018/2019/2020/2021 v&agrave; c&aacute;c bản vẽ dựng sẵn 2D với k&iacute;ch thước, ch&uacute; th&iacute;ch v&agrave; ph&acirc;n lớp, v.v.</p>\r\n<p>Ch&uacute;ng t&ocirc;i cung cấp dữ liệu ở bốn Cấp độ T&agrave;i liệu t&ugrave;y theo y&ecirc;u cầu&mdash; Cấp độ 1 (Sơ đồ mặt bằng), Cấp độ 2 (Sơ đồ độ cao v&agrave; m&aacute;i nh&agrave; b&ecirc;n ngo&agrave;i), Cấp độ 3 (C&aacute;c phần) v&agrave; Cấp độ 4 (Sơ đồ bố tr&iacute; mặt bằng)</p>\r\n<p>Nh&oacute;m lập m&ocirc; h&igrave;nh Scan to BIM của ch&uacute;ng t&ocirc;i c&oacute; kinh nghiệm tạo m&ocirc; h&igrave;nh BIM 3D đ&atilde; x&acirc;y dựng hoặc bản vẽ 2D gi&agrave;u th&ocirc;ng tin cho kh&aacute;ch h&agrave;ng để x&aacute;c nhận / lập kế hoạch / so s&aacute;nh thiết kế, kiểm tra can thiệp, MEP hoặc ph&aacute; dỡ c&aacute;c yếu tố x&acirc;y dựng hoặc bổ sung, t&agrave;i liệu về t&ograve;a nh&agrave; hiện c&oacute; điều kiện, số lượng cất c&aacute;nh v&agrave; dự tr&ugrave; ng&acirc;n s&aacute;ch.</p>\r\n<p>Ch&uacute;ng t&ocirc;i cung cấp dịch vụ Qu&eacute;t tới BIM (hay c&ograve;n gọi l&agrave; dịch vụ Lập m&ocirc; h&igrave;nh đ&aacute;m m&acirc;y điểm) cho c&aacute;c C&ocirc;ng ty Qu&eacute;t Laser, Nh&agrave; khảo s&aacute;t, Chủ sở hữu t&agrave;i sản, C&ocirc;ng ty thiết kế kiến ​​tr&uacute;c, C&ocirc;ng ty kỹ thuật MEP v&agrave; Tổng thầu hoặc c&ocirc;ng ty Quản l&yacute; x&acirc;y dựng. Kinh nghiệm của ch&uacute;ng t&ocirc;i bao gồm ph&aacute;t triển c&aacute;c m&ocirc; h&igrave;nh 3D BIM v&agrave; 2D CAD tham số nắm bắt c&aacute;c yếu tố kiến ​​tr&uacute;c, kết cấu v&agrave; MEP cho c&aacute;c dự &aacute;n kh&aacute;ch sạn, gi&aacute;o dục v&agrave; thương mại.</p>','<h1>Ứng dụng Qu&eacute;t đến BIM</h1>\r\n<p>Ch&uacute;ng t&ocirc;i hiểu một kế hoạch được thực hiện tốt sẽ cần những g&igrave; đối với bất kỳ Dự &aacute;n Trang bị / Cải tạo, T&aacute;i thiết v&agrave; Cải tạo n&agrave;o. Tất cả c&aacute;c quyết định dựa tr&ecirc;n dữ liệu như lập kế hoạch, ước t&iacute;nh, ph&acirc;n t&iacute;ch t&iacute;nh khả thi, v.v. t&ugrave;y thuộc v&agrave;o độ ch&iacute;nh x&aacute;c của m&ocirc; h&igrave;nh đ&atilde; x&acirc;y dựng được tạo từ Qu&eacute;t đ&aacute;m m&acirc;y điểm. Đ&aacute;m m&acirc;y điểm l&agrave; một tập hợp c&aacute;c điểm thể hiện ch&iacute;nh x&aacute;c c&aacute;c bề mặt của t&ograve;a nh&agrave; được sử dụng để tạo m&ocirc; h&igrave;nh BIM 3D hoặc / v&agrave; bản vẽ 2D được x&acirc;y dựng. Ch&uacute;ng t&ocirc;i c&oacute; thể l&agrave;m việc tr&ecirc;n cả h&igrave;nh ảnh dữ liệu khảo s&aacute;t bằng laser v&agrave; dữ liệu đ&aacute;m m&acirc;y điểm. Dịch vụ Qu&eacute;t tới BIM (dịch vụ Lập m&ocirc; h&igrave;nh đ&aacute;m m&acirc;y điểm) của ch&uacute;ng t&ocirc;i cũng &aacute;p dụng cho c&aacute;c dự &aacute;n Cơ sở hạ tầng như đường hầm, cầu, đường, v.v.</p>\r\n<p>Ch&uacute;ng t&ocirc;i cung cấp Cấp độ T&agrave;i liệu sau cho kh&aacute;ch h&agrave;ng của m&igrave;nh:</p>\r\n<p><strong>Tầng 1: Sơ đồ tầng</strong><br /><strong>Cấp độ 2: Sơ đồ độ cao v&agrave; m&aacute;i nh&agrave; b&ecirc;n ngo&agrave;i</strong><br /><strong>Cấp độ 3: Phần</strong><br /><strong>Cấp độ 4: Sơ đồ bố tr&iacute; địa điểm</strong></p>\r\n<p><br />Ch&uacute;ng t&ocirc;i c&oacute; kinh nghiệm ph&aacute;t triển cả tệp Revit (.rvt) v&agrave; CAD (.dwg) từ c&aacute;c định dạng qu&eacute;t kh&aacute;c nhau hoặc dữ liệu đ&aacute;m m&acirc;y điểm thường được chụp bằng m&aacute;y qu&eacute;t laser th&ocirc;ng dụng&mdash; M&aacute;y qu&eacute;t Leica Geosystems, Trimble, Faro Scanners, Reigl. Ch&uacute;ng t&ocirc;i cũng chuyển đổi dữ liệu định dạng kh&aacute;c (tức l&agrave; .fls, .e57, .pcg. .Obj, .ptg) sang định dạng sẵn s&agrave;ng cho Revit. Ch&uacute;ng t&ocirc;i tạo M&ocirc; h&igrave;nh 3D sẵn s&agrave;ng BIM gi&agrave;u th&ocirc;ng tin cho Y&ecirc;u cầu về kiến ​​tr&uacute;c, kết cấu v&agrave; MEPFP cũng như t&iacute;ch hợp kh&ocirc;ng c&oacute; xung đột.</p>','Quét sang BIM | Dịch vụ Point Cloud tới BIM','quet-sang-bim-dich-vu-point-cloud-toi-bim','Chúng tôi cung cấp Mô hình BIM được xây dựng theo thông số và chính xác và Mô hình CAD 2D mô tả các đường ống, tường, tấm, mặt phẳng mái, mặt tiền và cảnh quan trong và xung quanh tòa nhà. Chúng tôi cung cấp các mô hình có LOD 100 đến 500 cho khách hàng của mình bao gồm tất cả các Phần tử Kiến trúc, Kết cấu, MEPFP cùng với Phát hiện xung đột cho các Dự án Cải tạo, Tân trang, Trang bị thêm hoặc Tái thiết của họ.','BIM, BIM cơ bản',NULL),(3,2,'en','SketchUp software','SketchUp is a 3D modeling software, intended for architects, engineers, video game developers, film directors and related professions. This software was originally developed by @Last Software company, based in Boulder, Colorado, USA. This software stands out as a simple and fast idea expression tool with a graphical user interface.','<p>Currently, Sketchup software has been acquired, distributed &amp; developed by Trimble along with other famous products of Trimble such as Tekla Structures, Tekla Structural Designer...</p>\r\n<p><img src=\"https://www.sketchup.com/sites/www.sketchup.com/files/molecule_image/Bund-Pro-S2-Fun.png\" alt=\"SketchUp Pro\" /><br />Some salient features of SketchUp:</p>\r\n<p>No need for powerful hardware like other modeling software like &nbsp;3D Max, FormZ, Maya.</p>\r\n<p>An interface system with intelligent graphic pointer allows the user to construct a three-dimensional drawing in the two-dimensional space of the screen.</p>\r\n<p>Faces are simply defined based on a closed domain.</p>\r\n<p>Create simple blocks quickly with the \"push-pull\" tool</p>\r\n<p>Tool to edit block (extrude - widen) and create block according to given birth path (follow me tool)</p>\r\n<p>The ability to simulate, correct the angle of the sun at all times of the year as well as cover the viewing angles for near-instant effect.</p>\r\n<p>The drawing is &nbsp;rendered &nbsp;at high speed based on a well-simplified low-poly model system, with a unique presentation style.</p>\r\n<p>Extensive interoperability with other modeling software.</p>\r\n<p>Can be combined with external renderers (Renderer) to produce better images (etc. IRender, Podium, Indigo, Kerkythea...)</p>','<p>History:</p>\r\n<p>The first version of SketchUp was released in early 2001 with the aim of creating simple three-dimensional objects, however SketchUp soon found its place in the architecture and design market, after a few minor modifications. to match the characteristics of the professions. The decisive key to the success of the software lies in the recognition of curves, although not as deep as three-dimensional modeling software on the market, but has brought fast processing speed. However, this also limits SketchUp\'s ability to simulate reality.</p>\r\n<p>An effective application of this software is home design. After designing the model, users can combine using Google Earth to paste the newly designed house model on the image of the area where the lot is located, to see how it fits the whole scene. In addition, users can also share their designs with other users through the 3D warehouse feature of finished models from houses to furniture, appliances, vehicles, statues, bridges. ..</p>','SketchUp software','phan-mem-sketchup','SketchUp is a 3D modeling software, intended for architects, engineers, video game developers, film directors and related professions. This software was originally developed by @Last Software company, based in Boulder, Colorado, USA. This software stands out as a simple and fast idea expression tool with a graphical user interface.','BIM, Advance BIM',NULL),(4,2,'vi','Phần mềm SketchUp','SketchUp là một phần mềm mô hình hóa 3D, dành cho các kiến trúc sư, các kỹ sư, nhà phát triển trò chơi điện tử, các đạo diễn điện ảnh và các ngành nghề có liên quan. Phần mềm này khởi đầu được phát triển bởi công ty @Last Software, có trụ sở tại Boulder, Colorado, Mỹ. Phần mềm này nổi bật như một công cụ diễn tả ý tưởng đơn giản, nhanh gọn với giao diện đồ họa cho người sử dụng.','<p>Hiện tại phần mềm Sketchup đ&atilde; được h&agrave;ng Trimble mua lại ph&acirc;n phối &amp; ph&aacute;t triển c&ugrave;ng với c&aacute;c sản phẩm nổi tiếng kh&aacute;c của h&atilde;ng Trimble như Tekla Structures, Tekla Structural Designer...<br />&nbsp;</p>\r\n<p><img src=\"https://www.sketchup.com/sites/www.sketchup.com/files/molecule_image/Bund-Pro-S2-Fun.png\" alt=\"SketchUp Pro\" /></p>\r\n<h2>Một v&agrave;i đặc điểm nổi bật của SketchUp:</h2>\r\n<ul>\r\n<li>\r\n<p>Kh&ocirc;ng cần phần cứng mạnh như c&aacute;c phần mềm m&ocirc; h&igrave;nh h&oacute;a kh&aacute;c như&nbsp;<a class=\"new\" title=\"3D Max (trang chưa được viết)\" href=\"https://vi.wikipedia.org/w/index.php?title=3D_Max&amp;action=edit&amp;redlink=1\">3D Max</a>,&nbsp;<a class=\"new\" title=\"FormZ (trang chưa được viết)\" href=\"https://vi.wikipedia.org/w/index.php?title=FormZ&amp;action=edit&amp;redlink=1\">FormZ</a>,&nbsp;<a class=\"mw-disambig\" title=\"Maya\" href=\"https://vi.wikipedia.org/wiki/Maya\">Maya</a>.</p>\r\n</li>\r\n<li>\r\n<p>Hệ thống giao diện với con trỏ đồ họa th&ocirc;ng minh cho ph&eacute;p người sử dụng dựng h&igrave;nh vẽ ba chiều trong kh&ocirc;ng gian hai chiều của&nbsp;<a title=\"Thiết bị hiển thị\" href=\"https://vi.wikipedia.org/wiki/Thi%E1%BA%BFt_b%E1%BB%8B_hi%E1%BB%83n_th%E1%BB%8B\">m&agrave;n h&igrave;nh</a>.</p>\r\n</li>\r\n<li>\r\n<p>C&aacute;c mặt, diện (<em>face</em>) được định nghĩa đơn giản dựa tr&ecirc;n một miền kh&eacute;p k&iacute;n.</p>\r\n</li>\r\n<li>\r\n<p>Tạo khối đơn giản nhanh gọn bằng c&ocirc;ng cụ \"k&eacute;o-đẩy\" (<em>push-pull tool</em>)</p>\r\n</li>\r\n<li>\r\n<p>C&ocirc;ng cụ chỉnh sửa khối (<em>extrude - widen</em>) v&agrave; tạo khối theo đường sinh cho trước (<em>follow me tool</em>)</p>\r\n</li>\r\n<li>\r\n<p>Khả năng cho ph&eacute;p m&ocirc; phỏng, hiệu chỉnh g&oacute;c chiếu của mặt trời v&agrave;o tất cả c&aacute;c thời điểm trong năm cũng như bao qu&aacute;t c&aacute;c g&oacute;c nh&igrave;n cho hiệu quả gần như tức thời.</p>\r\n</li>\r\n<li>\r\n<p>Bản vẽ được&nbsp;<a title=\"Kết xuất đồ họa\" href=\"https://vi.wikipedia.org/wiki/K%E1%BA%BFt_xu%E1%BA%A5t_%C4%91%E1%BB%93_h%E1%BB%8Da\">kết xuất</a>&nbsp;(<em>render</em>) ở tốc độ cao dựa tr&ecirc;n tốt giản hệ m&ocirc; h&igrave;nh đa gi&aacute;c thấp (<em>low-poly</em>), c&oacute; phong c&aacute;ch tr&igrave;nh b&agrave;y độc đ&aacute;o.</p>\r\n</li>\r\n<li>\r\n<p>Khả năng giao tiếp rộng r&atilde;i với c&aacute;c phần mềm m&ocirc; h&igrave;nh kh&aacute;c.</p>\r\n</li>\r\n<li>\r\n<p>C&oacute; thể kết hợp với c&aacute;c tr&igrave;nh kết xuất ngo&agrave;i (Renderer) để cho ra những h&igrave;nh ảnh tốt hơn (etc. IRender, Podium, Indigo, Kerkythea...)<br />&nbsp;</p>\r\n</li>\r\n</ul>','<h2>Lịch sử:</h2>\r\n<p>Phi&ecirc;n bản đầu ti&ecirc;n của SketchUp được ph&aacute;t h&agrave;nh đầu năm&nbsp;<a title=\"2001\" href=\"https://vi.wikipedia.org/wiki/2001\">2001</a>&nbsp;với mục đ&iacute;ch tạo c&aacute;c đối tượng ba chiều đơn giản, tuy nhi&ecirc;n SketchUp đ&atilde; sớm t&igrave;m được vị tr&iacute; trong thị trường kiến tr&uacute;c v&agrave; thiết kết, sau khi c&oacute; một v&agrave;i sửa đổi nhỏ để ph&ugrave; hợp với đặc điểm của c&aacute;c ng&agrave;nh chuy&ecirc;n m&ocirc;n. Ch&igrave;a kh&oacute;a quyết định cho th&agrave;nh c&ocirc;ng của phần mềm nằm ở độ nhận biết c&aacute;c đường cong, tuy kh&ocirc;ng s&acirc;u như c&aacute;c phần mềm m&ocirc; h&igrave;nh h&oacute;a ba chiều tr&ecirc;n thị trường nhưng đ&atilde; đem lại tốc độ xử l&yacute; nhanh. Tuy nhi&ecirc;n ch&iacute;nh điều n&agrave;y cũng hạn chế khả năng m&ocirc; phỏng thực tế của SketchUp.</p>\r\n<p>Một ứng dụng hữu hiệu của phần mềm n&agrave;y l&agrave; thiết kế mẫu nh&agrave;. Sau khi thiết kế xong m&ocirc; h&igrave;nh, người d&ugrave;ng c&oacute; thể kết hợp sử dụng Google Earth để d&aacute;n mẫu nh&agrave; vừa thiết kế l&ecirc;n h&igrave;nh ảnh khu vực c&oacute; l&ocirc; đất đ&oacute;, để xem n&oacute; ph&ugrave; hợp với to&agrave;n cảnh ra sao. Ngo&agrave;i ra, người sử dụng cũng c&oacute; thể chia sẻ thiết kế của m&igrave;nh với những người d&ugrave;ng kh&aacute;c th&ocirc;ng qua t&iacute;nh năng 3D warehouse c&aacute;c m&ocirc; h&igrave;nh đ&atilde; ho&agrave;n th&agrave;nh từ nh&agrave; cửa cho tới đồ đạc, vật dụng, xe cộ, tượng, cầu...</p>','Phần mềm SketchUp','phan-mem-sketchup','SketchUp là một phần mềm mô hình hóa 3D, dành cho các kiến trúc sư, các kỹ sư, nhà phát triển trò chơi điện tử, các đạo diễn điện ảnh và các ngành nghề có liên quan. Phần mềm này khởi đầu được phát triển bởi công ty @Last Software, có trụ sở tại Boulder, Colorado, Mỹ. Phần mềm này nổi bật như một công cụ diễn tả ý tưởng đơn giản, nhanh gọn với giao diện đồ họa cho người sử dụng.','BIM, BIM cơ bản',NULL),(5,6,'en','Adobe Photoshop','Adobe Photoshop is a graphic editing software developed and published by Adobe Systems in 1988 on the Macintosh system. Photoshop is considered the market leader in bitmap image editing and is considered the standard for industries related to image editing. Since Photoshop version 7.0 was released in 2002, Photoshop has made a revolution in bitmap images. The latest version today is Adobe Photoshop CC.','<div id=\"tab-container\" class=\"tab-container list-tab-product  e-tab tab-product\" data-easytabs=\"true\">\r\n<div class=\"wrap-detail\">\r\n<article id=\"details\" class=\"baiviet active\">\r\n<p><strong>Adobe Photoshop CC - Create anything you can imagine.</strong></p>\r\n<p>The world\'s best photo and design apps are at the core of most creative projects. Photoshop CC can work on desktops and mobile devices to create and enhance images, design web and mobile apps, 3D artwork, videos, and more.&nbsp;</p>\r\n<p><span lang=\"vi\"><img src=\"https://www.consoft.vn/uploads/photoshop%20cc%202014.png\" alt=\"\" /></span></p>\r\n</article>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n</div>',NULL,'Adobe Photoshop','Cannonical Link [en]','Adobe Photoshop is a graphic editing software developed and published by Adobe Systems in 1988 on the Macintosh system. Photoshop is considered the market leader in bitmap image editing and is considered the standard for industries related to image editing. Since Photoshop version 7.0 was released in 2002, Photoshop has made a revolution in bitmap images. The latest version today is Adobe Photoshop CC.','Thẻ Meta Keyword [en]',NULL),(6,6,'vi','Adobe Photoshop','Adobe Photoshop là một phần mềm chỉnh sửa đồ họa được phát triển và phát hành bởi hãng Adobe Systems ra đời vào năm 1988 trên hệ máy Macintosh. Photoshop được đánh giá là phần mềm dẫn đầu thị trường về sửa ảnh bitmap và được coi là chuẩn cho các ngành liên quan tới chỉnh sửa ảnh. Từ phiên bản Photoshop 7.0 ra đời năm 2002, Photoshop đã làm lên một cuộc cách mạng về ảnh bitmap. Phiên bản mới nhất hiện nay là Adobe Photoshop CC.','<div id=\"tab-container\" class=\"tab-container list-tab-product  e-tab tab-product\" data-easytabs=\"true\">\r\n<div class=\"wrap-detail\">\r\n<article id=\"details\" class=\"baiviet active\">\r\n<p><span id=\"result_box\" lang=\"vi\"><strong>Adobe Photoshop CC - Tạo bất cứ điều g&igrave; bạn c&oacute; thể tưởng tượng.</strong><br /><br />Ứng dụng h&igrave;nh ảnh v&agrave; thiết kế tốt nhất thế giới l&agrave; cốt l&otilde;i của hầu hết c&aacute;c dự &aacute;n s&aacute;ng tạo.&nbsp;Photoshop CC c&oacute; thể l&agrave;m việc tr&ecirc;n m&aacute;y t&iacute;nh để b&agrave;n v&agrave; thiết bị di động để tạo v&agrave; n&acirc;ng cao h&igrave;nh ảnh, thiết kế ứng dụng web v&agrave; thiết bị di động, t&aacute;c phẩm nghệ thuật 3D, video v&agrave; hơn thế nữa.</span><br />&nbsp;</p>\r\n<p><span lang=\"vi\"><img src=\"https://www.consoft.vn/uploads/photoshop%20cc%202014.png\" alt=\"\" /></span></p>\r\n</article>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n</div>',NULL,'adobe-photoshop','Cannonical Link [vi]','Adobe Photoshop là một phần mềm chỉnh sửa đồ họa được phát triển và phát hành bởi hãng Adobe Systems ra đời vào năm 1988 trên hệ máy Macintosh. Photoshop được đánh giá là phần mềm dẫn đầu thị trường về sửa ảnh bitmap và được coi là chuẩn cho các ngành liên quan tới chỉnh sửa ảnh. Từ phiên bản Photoshop 7.0 ra đời năm 2002, Photoshop đã làm lên một cuộc cách mạng về ảnh bitmap. Phiên bản mới nhất hiện nay là Adobe Photoshop CC.','Thẻ Meta Keyword [vi]',NULL),(7,7,'en','BIM 5D','Like 3D and 4D, there are many specialized software to support you besides 3D modeling software. To do 5D, for example, there are some comrades like Causeway, CostX, Vico… Of course, this 5D part must be in charge of the estimating engineer.','<p>The big advantage of 5D BIM can be the volume extraction. Currently, there are still many companies that take off the volume by printing drawings on paper, coloring and measuring by hand. There are some companies that load the volume from the pdf file with software such as On-Screen Takeoff, Active Takeoff or Bluebeam&hellip; Only the beams with the floor and the columns can withstand it, but the equipment parts are completely unaffected. It\'s okay to improve the architecture, I don\'t know when it will be finished and if it\'s correct. With BIM, you already have a 3D model, so why not pick it up.</p>\r\n<p><br />Just note that different companies use different estimating software, and the methods of making estimates are also different, so the input data is sometimes different.</p>\r\n<p><br />Therefore, if only using the built-in mass extraction functions of 3D software (BIM Platform), eg Revit, the output volume is not usable (different format). So companies often have add-ins included to output the volume that matches the input of the specialized software they are using.I think in the future, 3D software manufacturers will not improve this volume extraction much, but leave the land for small software companies specializing in making integrated software according to the requirements of each company. Those of you who love software, can exploit this part to make products for sale.By the way, I also repeat the example of intentional modeling in part 4D to see that again, when making models, we must pay attention to the use of the parties later (intend model). For example, the wall is 10m high, when taking the total volume, it is the same, but to calculate the cost for each floor of the building, this wall must be divided into each floor, so the volume of each floor is accurate and the estimate is the same. That is not to mention the construction method, the construction of a wall of 10m in height once, the technical means are different from constructing many 3-4m sections.</p>','<p>In addition, the families must also have the appropriate information for you to extract (for example, the volume of steel in the beam by volume kg/m&sup3;, for example, so that when selling with a solid volume, you always have the volume of steel).</p>\r\n<p>&nbsp;</p>\r\n<p><br />So you have (1) volume from 3D, (2) method and organization of construction (to know what scaffolding to use and how many people for example) and (3) schedule (to know how long it takes to hire the scaffolding). education and use of labor for example) from 4D. You have (4) material prices and (5) labor prices from the company\'s database (the PolyBrain in the picture above). So you can make a price already.</p>\r\n<p><br />In Britain and France, there is no state unit price to apply. It is probably a market economy, so companies take care of their own prices for both materials and labor. Each company usually has a large database of prices, either learning from previous works, or under an annual agreement with suppliers (framework contract).</p>\r\n<p><br />In short, if the 3D models of the parties are properly built (with BIM Standards) and are intentional models, then you can do 3D-4D triathlons- 5D effectively during design and construction<br />Source: Long Thang</p>','Thẻ Meta Title [en]','Cannonical Link [en]','Like 3D and 4D, there are many specialized software to support you besides 3D modeling software. To do 5D, for example, there are some comrades like Causeway, CostX, Vico… Of course, this 5D part must be in charge of the estimating engineer.','Thẻ Meta Keyword [en]',NULL),(8,7,'vi','BIM 5D','Cũng như 3D và 4D, có khá nhiều phần mềm chuyên dụng hỗ trợ các bạn bên cạnh các phần mềm làm mô hình 3D. Để làm 5D chẳng hạn, có một số đồng chí như Causeway, CostX, Vico… Dĩ nhiên phần 5D này phải được phụ trách bởi kỹ sư dự toán (estimating engineer).','<div>Ưu điểm lớn của BIM 5D c&oacute; thể l&agrave; đoạn tr&iacute;ch xuất khối lượng. Hiện tại vẫn c&ograve;n nhiều c&ocirc;ng ty b&oacute;c t&aacute;ch khối lượng bằng c&aacute;ch in bản vẽ ra giấy, t&ocirc; m&agrave;u rồi đo bằng tay. C&oacute; một số c&ocirc;ng ty th&igrave; bốc khối lượng từ file pdf bằng c&aacute;c phần mềm như On-Screen Takeoff, Active Takeoff hoặc Bluebeam&hellip; Chỉ c&oacute; b&eacute;ton l&agrave; dầm với s&agrave;n với cột th&igrave; c&ograve;n chịu được chứ đụng đến c&aacute;c phần trang thiết bị với ho&agrave;n thiện kiến tr&uacute;c th&igrave; th&ocirc;i rồi, kh&ocirc;ng biết l&uacute;c n&agrave;o mới xong v&agrave; c&oacute; ch&iacute;nh x&aacute;c kh&ocirc;ng. Với BIM, bạn c&oacute; sẵn m&ocirc; h&igrave;nh 3D th&igrave; tại sao kh&ocirc;ng bốc lu&ocirc;n .</div>\r\n<div>&nbsp;</div>\r\n<div>Chỉ lưu &yacute; l&agrave; c&aacute;c c&ocirc;ng ty kh&aacute;c nhau sử dụng phần mềm dự to&aacute;n kh&aacute;c nhau, phương ph&aacute;p l&agrave;m dự to&aacute;n cũng kh&aacute;c nhau n&ecirc;n số liệu đầu v&agrave;o nhiều khi kh&aacute;c nhau.</div>\r\n<div>&nbsp;</div>\r\n<div>Bởi vậy nếu chỉ d&ugrave;ng c&aacute;c chức năng tr&iacute;ch xuất khối lượng c&oacute; sẳn của c&aacute;c phần mềm 3D (BIM Platform), v&iacute; dụ Revit, th&igrave; khối lượng đầu ra kh&ocirc;ng d&ugrave;ng được (kh&aacute;c format). N&ecirc;n c&aacute;c c&ocirc;ng ty thường c&oacute; c&aacute;c Add-in đi k&egrave;m để xuất khối lượng ph&ugrave; hợp với đầu v&agrave;o của c&aacute;c phần mềm chuy&ecirc;n dụng m&agrave; m&igrave;nh đang d&ugrave;ng.</div>\r\n<div>&nbsp;</div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div>M&igrave;nh nghĩ trong tương lai, c&aacute;c nh&agrave; sản xuất phần mềm 3D cũng kh&ocirc;ng cải tiến phần tr&iacute;ch xuất khối lượng n&agrave;y lắm m&agrave; để mảnh đất cho c&aacute;c c&ocirc;ng ty phần mềm nhỏ chuy&ecirc;n l&agrave;m c&aacute;c phần mềm t&iacute;ch hợp theo y&ecirc;u cầu của từng c&ocirc;ng ty. C&aacute;c bạn n&agrave;o y&ecirc;u th&iacute;ch phần mềm, c&oacute; thể khai th&aacute;c phần n&agrave;y để l&agrave;m sản phẩm b&aacute;n được .</div>\r\n<div>&nbsp;</div>\r\n<div>Nh&acirc;n tiện m&igrave;nh cũng nhắc lại c&aacute;i v&iacute; dụ m&ocirc; h&igrave;nh c&oacute; chủ &yacute; ở phần 4D để thấy l&agrave; một lần nữa, khi l&agrave;m m&ocirc; h&igrave;nh phải ch&uacute; &yacute; đến việc sử dụng của c&aacute;c b&ecirc;n về sau (intend model). V&iacute; dụ c&aacute;i tường cao 10m, khi lấy khối lượng tổng th&igrave; như nhau nhưng để t&iacute;nh gi&aacute; th&agrave;nh cho từng tầng của c&ocirc;ng tr&igrave;nh th&igrave; phải chia tường n&agrave;y th&agrave;nh từng tầng, như vậy khối lượng từng tầng mới ch&iacute;nh x&aacute;c v&agrave; dự to&aacute;n cũng vậy. Đấy l&agrave; chưa n&oacute;i đến phương ph&aacute;p thi c&ocirc;ng, chuyện thi c&ocirc;ng tường 10m chiều cao một lần th&igrave; phương tiện kỹ thuật kh&aacute;c hẳn thi c&ocirc;ng th&agrave;nh nhiều đoạn 3-4m.</div>\r\n</div>','<div>\r\n<div>B&ecirc;n cạnh đấy, c&aacute;c family cũng phải c&oacute; c&aacute;c th&ocirc;ng tin ph&ugrave; hợp để bạn tr&iacute;ch xuất (v&iacute; dụ khối lượng th&eacute;p trong dầm theo thể t&iacute;ch kg/m&sup3; chẳng hạn để khi b&aacute;n c&oacute; thể t&iacute;ch bếton, bạn c&oacute; lu&ocirc;n khối lượng th&eacute;p).</div>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><img class=\"aligncenter\" src=\"http://vibim.com.vn/images/5Dprocess%203.png\" alt=\"\" align=\"\" border=\"0px\" /></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div>Vậy l&agrave; c&aacute;c bạn c&oacute; (1) khối lượng từ 3D, (2) Phương ph&aacute;p v&agrave; tổ chức thi c&ocirc;ng (để biết d&ugrave;ng gi&agrave;n gi&aacute;o g&igrave; v&agrave; bao nhi&ecirc;u người chẳng hạn) v&agrave; (3) tiến độ (để biết thời gian thu&ecirc; gi&agrave;n gi&aacute;o v&agrave; sử dụng nh&acirc;n c&ocirc;ng v&iacute; dụ thế) từ 4D. C&aacute;c bạn c&oacute; (4) gi&aacute; vật liệu v&agrave; (5) gi&aacute; nh&acirc;n c&ocirc;ng từ cơ sở dữ liệu của c&ocirc;ng ty (c&aacute;i PolyBrain ở h&igrave;nh tr&ecirc;n). Vậy l&agrave; c&aacute;c bạn c&oacute; thể l&agrave;m gi&aacute; được rồi .</div>\r\n<div>&nbsp;</div>\r\n<div>Ở Anh với Ph&aacute;p th&igrave; kh&ocirc;ng c&oacute; c&aacute;i đơn gi&aacute; nh&agrave; nước n&agrave;o để &aacute;p dụng cả. Chắc l&agrave; kinh tế thị trường n&ecirc;n c&aacute;c c&ocirc;ng ty tự lo gi&aacute; với nhau về cả vật liệu lẫn nh&acirc;n c&ocirc;ng. Mỗi c&ocirc;ng ty thường c&oacute; một cơ sở dữ liệu lớn lưu trử c&aacute;c gi&aacute; th&agrave;nh, hoặc l&agrave; r&uacute;t kinh nghiệm từ c&aacute;c c&ocirc;ng tr&igrave;nh trước, hoặc l&agrave; theo thỏa thuận hằng năm với c&aacute;c nh&agrave; cung cấp (framework contract)</div>\r\n<div>&nbsp;</div>\r\n<div>T&oacute;m lại nếu m&ocirc; h&igrave;nh 3D của c&aacute;c b&ecirc;n được dựng một c&aacute;ch ph&ugrave; hợp (c&ugrave;ng BIM Standards) v&agrave; l&agrave; c&aacute;c m&ocirc; h&igrave;nh c&oacute; chủ &yacute; (intend model) th&igrave; c&aacute;c bạn ho&agrave;n to&agrave;n c&oacute; thể thực hiện c&aacute;c bộ m&ocirc;n phối hợp 3D-4D-5D một c&aacute;ch hiệu quả trong qu&aacute; tr&igrave;nh thiết kế v&agrave; thi c&ocirc;ng</div>\r\n<div>Nguồn: Long Thang</div>\r\n</div>','Thẻ Meta Title [vi]','Cannonical Link [vi]','Cũng như 3D và 4D, có khá nhiều phần mềm chuyên dụng hỗ trợ các bạn bên cạnh các phần mềm làm mô hình 3D. Để làm 5D chẳng hạn, có một số đồng chí như Causeway, CostX, Vico… Dĩ nhiên phần 5D này phải được phụ trách bởi kỹ sư dự toán (estimating engineer).','Thẻ Meta Keyword [vi]',NULL),(9,8,'en','Navisworks Manage – Tool for BIM era project managers','Navisworks Manage – Tool for Project Managers in the BIM Age As project managers, we cannot help but know BIM and BIM-supporting tools. Among the Bim Tools for project managers is Navisworks Manage.','<p>With Autodesk\'s Navisworks solution group, customers can combine design data generated from multiple separate software applications, such as AutoCAD, Revits, Infraworks, Sketchup, etc., with information about shapes and in many different formats and file sizes. The result is a holistic view of the project that helps stakeholders make sound design decisions, improves construction documentation accuracy, and better estimates efficiency and planning. plan for the project.<br />The Navisworks software family offers three products: &nbsp;Navisworks Freedom, Naviswork Simulation and Navisworks Manage; These products provide Investors, Design Engineers, Construction Contractors, Management Consultants&hellip; an accurate tool to help them collaborate, coordinate and exchange work information really effectively. than. Naviswork Manage is the highest of the three products above. So just learning and understanding how to use Navisworks Manage is OK.<br />In this article, Pope Francis would like to share with you, especially those who work in the field of project management, some information about this wonderful software.</p>\r\n<p>Autodesk Navisworks software helps Architects, Structural Engineers &amp; Systems Engineers greatly improve control over the outputs of design or construction projects. Especially, it effectively supports project managers with BIM 4D, 5D support.</p>','<p>PROJECT REVIEW The outstanding advantage of Navisworks is that it allows the integration of 3D data from many different sources and is extremely fast. Even information from photo files or from laser scanners is effectively exploited by this application.Navisworks provides 02 toolkits:&ndash; Design project evaluation toolkit: has functions beyond dominant, allowing users to measure distance &amp; azimuth; area calculation; storing, organizing and reporting 3D views of a truly scientific project; Create plan or cross-sectional views anywhere in the central model file for detailed analysis.&ndash; Design collaboration toolkit: exchange of information in design projects. design has been raised to a new level by Navisworks to improve teamwork; directly give comments and design suggestions on the model; support searching and extracting feedback from other members; Create and share simulation footage of the project.</p>\r\n<p><br />ANALYSIS &amp; ANALYSIS FUNCTION GROUP (SIMULATION &amp; ANALYSIS) Navisworks is equipped with a library of 1000 different types of materials. With a function that allows you to configure settings for initializing simulated images such as adjusting light sources, displaying materials, background, foreground and creating scenarios like in real space (depending on geographical location). &amp; climate of each region) will give us the most intuitive &amp; realistic view even before the project is fully built.<br />A new function and demonstrating the core value of Navisworks is that it allows us to create Object animations to serve the analysis of physical collisions as well as workspace conflicts. between components and devices. All these geometric interactions and overlapping areas of influence between objects will be cataloged by Navisworks into specific categories, with instructions attached, precisely positioned in the central and linked model. with the 4D schedule to improve the construction plan.</p>\r\n<p><br />The 4D construction schedule (4D Scheduling) is the difference of Navisworks and promises to bring many interesting experiences to the Construction Contractors as well as the Project Management Consultants. In addition to the information showing the Job Title, Implementation Time, Work Order, for the first time the Construction Progress Table is modeled and the Progress Engineers can see their works \"big\". gradually&rdquo; over the years. Moreover, setting any time in the construction schedule will allow us to observe the project in the context of each item, each part of the work in progress, forming over time.<br />You can watch more videos below to get a glimpse of the progress simulation function on Navisworks:</p>\r\n<p><br />GROUP COORDINATION Detecting physical collisions, workspace conflicts and effectively managing them is the highlight of the Navisworks product line in construction management. Anticipating potential problems before construction begins saves costs by reducing delays and re-doing a task.</p>\r\n<p><br />In addition to the detection function, Navisworks also equips us with a tool to help check those collisions and conflicts in 3D space, this is really easy and the remedial decisions will be made quickly. and accurate. After checking, those animations will be closely linked to the 4D schedule and we have complete control over whether the issue has been fully resolved, over time, conflicts whether it is a re-occurrence or a potential hazard to the building.</p>\r\n<p><br />GROUP VIEWING (PROJECT VIEWING) Simply Navisworks equips a tool that allows us to create simulation movies (Walkthrough) to explore our central model in every nook and cranny. The most detailed in 3D space.</p>','Thẻ Meta Title [en]','Cannonical Link [en]','Navisworks Manage – Tool for Project Managers in the BIM Age As project managers, we cannot help but know BIM and BIM-supporting tools. Among the Bim Tools for project managers is Navisworks Manage.','Thẻ Meta Keyword [en]',NULL),(10,8,'vi','Navisworks Manage – Công cụ dành cho người quản lý dự án thời đại BIM','Là những người làm quản lý dự án chúng ta không thể không biết tới BIM và những công cụ hỗ trợ BIM được. Trong số những Bim Tools dành cho nhà quản lý dự án có Navisworks Manage.','<p>Với nh&oacute;m giải ph&aacute;p Navisworks của Autodesk, kh&aacute;ch h&agrave;ng c&oacute; thể tổ hợp c&aacute;c dữ liệu thiết kế được khởi tạo từ nhiều ứng dụng phần mềm ri&ecirc;ng biệt, v&iacute; dụ như AutoCAD, Revits, Infraworks, Sketchup&hellip;, với th&ocirc;ng tin về h&igrave;nh khối v&agrave; dưới nhiều định dạng, dung lượng tệp lưu trữ kh&aacute;c nhau. Kết quả l&agrave; một c&aacute;i nh&igrave;n tổng thể về dự &aacute;n gi&uacute;p cho c&aacute;c th&agrave;nh vi&ecirc;n tham gia đưa ra được những quyết định thiết kế đ&uacute;ng đắn, n&acirc;ng cao t&iacute;nh ch&iacute;nh x&aacute;c của hồ sơ x&acirc;y dựng v&agrave; dự t&iacute;nh tốt hơn về hiệu quả cũng như lập kế hoạch cho dự &aacute;n.<br />Họ phần mềm Navisworks đưa ra 03 sản phẩm:&nbsp;<strong>Navisworks Freedom, Naviswork Simulation v&agrave; Navisworks Manage</strong>; những sản phẩm n&agrave;y cung cấp cho c&aacute;c Chủ đầu tư, Kỹ sư thiết kế, Nh&agrave; thầu thi c&ocirc;ng, Tư vấn quản l&yacute;&hellip; một c&ocirc;ng cụ ch&iacute;nh x&aacute;c gi&uacute;p họ cộng t&aacute;c, điều phối v&agrave; trao đổi th&ocirc;ng tin c&ocirc;ng việc thực sự hiệu quả hơn. Naviswork Manage l&agrave; sản phẩm cao nhất trong 3 sản phẩm tr&ecirc;n. N&ecirc;n chỉ cần học v&agrave; hiểu được c&aacute;ch d&ugrave;ng Navisworks Manage l&agrave; OK.<br />Trong b&agrave;i viết n&agrave;y ĐTC xin chia sẻ với c&aacute;c bạn, đặc biệt c&aacute;c bạn l&agrave;m trong lĩnh vực quản l&yacute; dự &aacute;n một v&agrave;i th&ocirc;ng tin về phần mềm tuyệt vời n&agrave;y.</p>\r\n<p>Phần mềm Navisworks của Autodesk hỗ trợ c&aacute;c Kiến tr&uacute;c sư, Kết cấu sư &amp; Hệ thống sư n&acirc;ng cao đ&aacute;ng kể c&ocirc;ng t&aacute;c kiểm so&aacute;t c&aacute;c sản phẩm đầu ra của đồ &aacute;n thiết kế hay c&ocirc;ng tr&igrave;nh x&acirc;y dựng. Đặc biệt n&oacute; hỗ trợ đắc lực cho những người l&agrave;m quản l&yacute; dự &aacute;n với hỗ trợ BIM 4D, 5D.</p>','<p><strong>NH&Oacute;M CHỨC NĂNG Đ&Aacute;NH GI&Aacute; DỰ &Aacute;N (PROJECT REVIEW)</strong>Ưu điểm vượt trội của Navisworks l&agrave; cho ph&eacute;p t&iacute;ch hợp c&aacute;c dữ liệu 3D từ rất nhiều nguồn kh&aacute;c nhau v&agrave; cực kỳ nhanh ch&oacute;ng. Thậm ch&iacute; c&aacute;c th&ocirc;ng tin từ tệp ảnh chụp hoặc từ thiết bị qu&eacute;t laser cũng được khai th&aacute;c hiệu quả bởi ứng dụng n&agrave;y.<em>Navisworks cung cấp 02 bộ c&ocirc;ng cụ:</em><strong>&ndash; Bộ c&ocirc;ng cụ đ&aacute;nh gi&aacute; đồ &aacute;n thiết kế:</strong>&nbsp;c&oacute; những chức năng vượt trội, cho ph&eacute;p người d&ugrave;ng đo đạc khoảng c&aacute;ch &amp; g&oacute;c phương vị; t&iacute;nh to&aacute;n diện t&iacute;ch; lưu trữ, tổ chức v&agrave; lập b&aacute;o c&aacute;o c&aacute;c khung nh&igrave;n 3D của dự &aacute;n thực sự khoa học; tạo ra những khung nh&igrave;n mặt bằng hay mặt cắt ngang ở bất cứ vị tr&iacute; n&agrave;o của tệp m&ocirc; h&igrave;nh trung t&acirc;m để phục vụ ph&acirc;n t&iacute;ch chi tiết.<strong>&ndash; Bộ c&ocirc;ng cụ cộng t&aacute;c thiết kế:</strong>&nbsp;c&ocirc;ng t&aacute;c trao đổi th&ocirc;ng tin trong đồ &aacute;n thiết kế đ&atilde; được Navisworks n&acirc;ng l&ecirc;n một tầm cao mới nhằm cải thiện năng lực l&agrave;m việc theo nh&oacute;m;&nbsp; trực tiếp đưa ra c&aacute;c b&igrave;nh luận, g&oacute;p &yacute; thiết kế tr&ecirc;n m&ocirc; h&igrave;nh; hỗ trợ t&igrave;m kiếm v&agrave; tr&iacute;ch xuất c&aacute;c th&ocirc;ng tin phản hồi từ c&aacute;c th&agrave;nh vi&ecirc;n kh&aacute;c; khởi tạo v&agrave; chia sẻ c&aacute;c thước phim giả lập về c&ocirc;ng tr&igrave;nh.</p>\r\n<p><br /><strong>NH&Oacute;M CHỨC NĂNG PH&Acirc;N T&Iacute;CH &amp; M&Ocirc; PHỎNG (SIMULATION &amp; ANALYSIS)</strong>Navisworks được trang bị sẵn bộ thư viện gồm 1000 chủng loại vật liệu kh&aacute;c nhau. Với chức năng cho ph&eacute;p định h&igrave;nh c&aacute;c thiết lập về khởi tạo ảnh giả lập như điều chỉnh nguồn s&aacute;ng, thể hiện vật tư, hậu cảnh, tiền cảnh v&agrave; tạo ra c&aacute;c kịch bản như trong kh&ocirc;ng gian thực (t&ugrave;y theo vị tr&iacute; địa l&yacute; &amp; kh&iacute; hậu từng v&ugrave;ng miền) sẽ mang đến cho ch&uacute;ng ta c&aacute;i nh&igrave;n trực quan nhất &amp; s&aacute;t thực nhất trước cả khi dự &aacute;n được x&acirc;y dựng ho&agrave;n chỉnh.<br />Một chức năng mới v&agrave; thể hiện gi&aacute; trị cốt l&otilde;i của Navisworks đ&oacute; l&agrave; cho ph&eacute;p ch&uacute;ng ta tạo ra c&aacute;c hoạt vật (Object animation) để phục vụ c&ocirc;ng t&aacute;c ph&acirc;n t&iacute;ch sự va chạm vật l&yacute; cũng như xung đột phạm vi kh&ocirc;ng gian l&agrave;m việc giữa c&aacute;c cấu kiện, thiết bị. Tất cả những sự tương t&aacute;c h&igrave;nh học v&agrave; chồng ch&eacute;o v&ugrave;ng ảnh hưởng n&agrave;y giữa c&aacute;c đối tượng sẽ được Navisworks thống k&ecirc; th&agrave;nh danh mục cụ thể, c&oacute; gắn k&egrave;m c&aacute;c chỉ dẫn, định vị ch&iacute;nh x&aacute;c trong m&ocirc; h&igrave;nh trung t&acirc;m v&agrave; được li&ecirc;n kết với tiến độ 4D nhằm cải thiện kế hoạch thi c&ocirc;ng x&acirc;y dựng.</p>\r\n<figure class=\"wp-block-image\"><a href=\"https://3.bp.blogspot.com/-S9FPq2zAI_g/WnAXDcfoipI/AAAAAAAAPnA/tw4Yf_jNwpkE5ttfmJ-r0b5GcO44AzsvACLcBGAs/s1600/5d-project-scheduling-with-navisworks-manage.jpg\"><img class=\"lazyloaded\" src=\"https://3.bp.blogspot.com/-S9FPq2zAI_g/WnAXDcfoipI/AAAAAAAAPnA/tw4Yf_jNwpkE5ttfmJ-r0b5GcO44AzsvACLcBGAs/s640/5d-project-scheduling-with-navisworks-manage.jpg\" alt=\"\" data-lazy-src=\"https://3.bp.blogspot.com/-S9FPq2zAI_g/WnAXDcfoipI/AAAAAAAAPnA/tw4Yf_jNwpkE5ttfmJ-r0b5GcO44AzsvACLcBGAs/s640/5d-project-scheduling-with-navisworks-manage.jpg\" data-was-processed=\"true\" /></a></figure>\r\n<p><em>Tiến độ thi c&ocirc;ng 4D (4D Scheduling) ch&iacute;nh l&agrave; điểm kh&aacute;c biệt của Navisworks v&agrave; hứa hẹn sẽ đem lại nhiều trải nghiệm th&uacute; vị cho c&aacute;c Nh&agrave; thầu thi c&ocirc;ng cũng như Tư vấn QLDA</em>. Ngo&agrave;i c&aacute;c th&ocirc;ng tin thể hiện T&ecirc;n đầu việc, Thời gian thực hiện, Tr&igrave;nh tự c&ocirc;ng t&aacute;c, lần đầu ti&ecirc;n Bảng tiến độ thi c&ocirc;ng x&acirc;y dựng được m&ocirc; h&igrave;nh h&oacute;a v&agrave; c&aacute;c Kỹ sư tiến độ c&oacute; thể nh&igrave;n thấy c&ocirc;ng tr&igrave;nh của m&igrave;nh &ldquo;lớn dần&rdquo; l&ecirc;n theo năm th&aacute;ng. Hơn nữa, việc ấn định một thời điểm bất kỳ trong tiến độ thi c&ocirc;ng sẽ cho ch&uacute;ng ta quan s&aacute;t được dự &aacute;n trong bối cảnh từng hạng mục, từng bộ phận c&ocirc;ng tr&igrave;nh đang dang dở h&igrave;nh th&agrave;nh theo thời gian.<br /><em>Bạn c&oacute; thể xem th&ecirc;m video dưới đ&acirc;y để hiểu sơ qua về chức năng m&ocirc; phỏng tiến độ tr&ecirc;n Navisworks:</em></p>\r\n<figure><iframe class=\"lazyloading\" src=\"https://www.youtube.com/embed/6cwm6tDXU0s\" width=\"100%\" height=\"315\" allowfullscreen=\"\" data-was-processed=\"true\"></iframe></figure>\r\n<p><strong>NH&Oacute;M CHỨC NĂNG ĐIỀU PHỐI (COORDINATION)&nbsp;</strong>D&ograve; t&igrave;m sự va chạm vật l&yacute;, xung đột v&ugrave;ng kh&ocirc;ng gian l&agrave;m việc v&agrave; thực hiện quản l&yacute; ch&uacute;ng một c&aacute;ch hiệu quả ch&iacute;nh l&agrave; điểm nổi bật của d&ograve;ng sản phẩm Navisworks trong quản l&yacute; thi c&ocirc;ng. Việc lường trước được c&aacute;c vấn đề tiềm t&agrave;ng từ trước khi triển khai x&acirc;y dựng gi&uacute;p tiết kiệm chi ph&iacute; th&ocirc;ng qua sự giảm thiểu c&aacute;c chậm trễ cũng như sự l&agrave;m đi l&agrave;m lại một c&ocirc;ng t&aacute;c n&agrave;o đ&oacute;.</p>\r\n<figure class=\"wp-block-image\"><a href=\"https://3.bp.blogspot.com/-MaZkX83izGY/WnAXVvFNwKI/AAAAAAAAPnE/lmOgbR3t2zEYzkMeAfHPZ7vZ6sC185AfgCLcBGAs/s1600/kiem-tra-va-cham-trong-navisworks.png\"><img class=\"lazyloaded\" src=\"https://3.bp.blogspot.com/-MaZkX83izGY/WnAXVvFNwKI/AAAAAAAAPnE/lmOgbR3t2zEYzkMeAfHPZ7vZ6sC185AfgCLcBGAs/s640/kiem-tra-va-cham-trong-navisworks.png\" alt=\"\" data-lazy-src=\"https://3.bp.blogspot.com/-MaZkX83izGY/WnAXVvFNwKI/AAAAAAAAPnE/lmOgbR3t2zEYzkMeAfHPZ7vZ6sC185AfgCLcBGAs/s640/kiem-tra-va-cham-trong-navisworks.png\" data-was-processed=\"true\" /></a></figure>\r\n<p>Ngo&agrave;i chức năng d&ograve; t&igrave;m, Navisworks c&ograve;n trang bị cho ch&uacute;ng ta c&ocirc;ng cụ gi&uacute;p kiểm tra c&aacute;c va đụng, xung đột đ&oacute; trong kh&ocirc;ng gian 3D, điều n&agrave;y thực sự dễ d&agrave;ng v&agrave; c&aacute;c quyết định khắc phục sẽ được đưa ra một c&aacute;ch nhanh ch&oacute;ng v&agrave; chuẩn x&aacute;c.Sau khi kiểm tra, c&aacute;c hoạt vật đ&oacute; sẽ được li&ecirc;n kết chặt chẽ đến tiến độ 4D v&agrave; ch&uacute;ng ta ho&agrave;n to&agrave;n kiểm so&aacute;t được xem vấn đề đ&oacute; đ&atilde; được giải quyết thấu đ&aacute;o chưa, theo thời gian, những xung đột đ&oacute; c&oacute; thể t&aacute;i hiện hoặc l&agrave; một mối nguy tiềm t&agrave;ng với c&ocirc;ng tr&igrave;nh hay kh&ocirc;ng.</p>\r\n<p><br /><strong>NH&Oacute;M CHỨC NĂNG QUAN S&Aacute;T (PROJECT VIEWING)</strong>Chỉ đơn giản l&agrave; Navisworks trang bị một c&ocirc;ng cụ cho ph&eacute;p ch&uacute;ng ta tạo ra c&aacute;c thước phim giả lập (Walkthrough) để kh&aacute;m ph&aacute; m&ocirc; h&igrave;nh trung t&acirc;m của m&igrave;nh tại từng ng&oacute;c ng&aacute;ch, từng vị tr&iacute; chi tiết nhất trong kh&ocirc;ng gian 3D.</p>','Thẻ Meta Title [vi]','Cannonical Link [vi]','Là những người làm quản lý dự án chúng ta không thể không biết tới BIM và những công cụ hỗ trợ BIM được. Trong số những Bim Tools dành cho nhà quản lý dự án có Navisworks Manage.','Thẻ Meta Keyword [vi]',NULL),(11,9,'en','Dynamo: Sandbox or Studio?','Users often wonder about Dynamo like this: they are often familiar with Revit and are looking for more advanced & sophisticated ways to control the creation, arrangement or analysis of BIM objects in a project. Unmatched Dynamo, originally developed as a visual programming tool for Revit.','<p>However, over the past 10 years, Dynamo has expanded compatibility with Civil3D, Alias ​​Design, Formit, and Advance Steel. Standalone worlds are created independent of Revit, and are available as a full version with Dynamo Studio or a Dynamo Sandbox open source developer edition.</p>\r\n<p><br />You may be wondering&hellip;</p>\r\n<p>What is the difference between Dynamo Studio and Dynamo Sandbox and which one is better for me?<br />Dynamo experts Zach Kron and Sol Amour have the most concise descriptions of each product and the audience they are aimed at:<br />Dynamo Studio<br />What is it?<br />Dynamo Studio is the core technology with Autodesk geometry tools and access to cloud services without any other software prerequisites.</p>\r\n<p>Who is it for?<br />For those of you in the education industry, we hope this can become a more widely accessible teaching tool. For office people, we hope this can be a bridge between non-Revit users and Revit-based projects. We hope this allows you to work on Dynamo sketches on the metro or talk to consultants and collaborators on other platforms like Navis and Rhino, and opens up the possibility of calculation accounting for users beyond traditional BIM.</p>\r\n<p>Dynamo Sandbox<br />What is it?<br />DynamoSandbox.exe is a free Dynamo core technology (scripting language, nodemap, execution engine) that can use some of the geometry tools available in Revit and does not have the ability to log in to services. cloud service.</p>','<p>Who is it for?<br />The Dynamo Sandbox is for package developers and others working with Dynamo code who want to stay on top of the latest and greatest coming out. Sandbox can be used as a general programming or orchestration interface for other programs because it can be run without installing any other Autodesk programs. As a BIM Manager, you can test host-specific packages in a secure environment prior to deployment.</p>\r\n<p>In the end, I only recommend Dynamo Sandbox to BIM Managers, package developers or proficient users who are already familiar with Dynamo. You can find the latest builds for Dynamo Sandbox, including daily builds at DynamoBuilds.com.</p>\r\n<p>For other users who want access to Dynamo\'s intuitive programming interface but don\'t need to access Revit objects through the Revit API, then Dynamo Studio is the best choice. As mentioned above, Dynamo Studio is stable and has access to cloud services, which makes it available on Sandbox. Dynamo Studio can run on platforms that Revit cannot run easily, such as ultrabooks or tablets running Windows 10; Expand the places where you can be productive.</p>','Thẻ Meta Title [en]','Cannonical Link [en]','Người dùng thường lăn tăn về Dynamo kiểu như: họ thường quen thuộc với Revit và đang tìm kiếm các cách cao cấp & tinh vi hơn để kiểm soát việc tạo, sắp xếp hoặc phân tích các đối tượng BIM trong một dự án. Dynamo vô đối, ban đầu được phát triển như một công cụ lập trình trực quan cho Revit.','Thẻ Meta Keyword [en]',NULL),(12,9,'vi','Dynamo: Sandbox hay Studio?','Người dùng thường lăn tăn về Dynamo kiểu như: họ thường quen thuộc với Revit và đang tìm kiếm các cách cao cấp & tinh vi hơn để kiểm soát việc tạo, sắp xếp hoặc phân tích các đối tượng BIM trong một dự án. Dynamo vô đối, ban đầu được phát triển như một công cụ lập trình trực quan cho Revit.','<p>Tuy nhi&ecirc;n, trong 10 năm qua, Dynamo đ&atilde; mở rộng khả năng tương th&iacute;ch với Civil3D, Alias Design, Formit v&agrave; Advance Steel. Thế giới độc lập được tạo ra kh&ocirc;ng phụ thuộc v&agrave;o Revit, v&agrave; c&oacute; sẵn dưới dạng phi&ecirc;n bản đầy đủ với Dynamo Studio hoặc phi&ecirc;n bản d&agrave;nh cho nh&agrave; ph&aacute;t triển nguồn mở Dynamo Sandbox.</p>\r\n<figure class=\"wp-block-image size-large\"><img class=\"wp-image-12040 lazyloaded\" src=\"https://vietnambim.net/wp-content/uploads/2021/03/image-1024x445.png\" srcset=\"https://vietnambim.net/wp-content/uploads/2021/03/image-1024x445.png 1024w, https://vietnambim.net/wp-content/uploads/2021/03/image-300x130.png 300w, https://vietnambim.net/wp-content/uploads/2021/03/image-768x334.png 768w, https://vietnambim.net/wp-content/uploads/2021/03/image-696x303.png 696w, https://vietnambim.net/wp-content/uploads/2021/03/image-966x420.png 966w, https://vietnambim.net/wp-content/uploads/2021/03/image.png 1060w\" alt=\"\" data-lazy-src=\"https://vietnambim.net/wp-content/uploads/2021/03/image-1024x445.png\" data-lazy-srcset=\"https://vietnambim.net/wp-content/uploads/2021/03/image-1024x445.png 1024w, https://vietnambim.net/wp-content/uploads/2021/03/image-300x130.png 300w, https://vietnambim.net/wp-content/uploads/2021/03/image-768x334.png 768w, https://vietnambim.net/wp-content/uploads/2021/03/image-696x303.png 696w, https://vietnambim.net/wp-content/uploads/2021/03/image-966x420.png 966w, https://vietnambim.net/wp-content/uploads/2021/03/image.png 1060w\" data-lazy-sizes=\"(max-width: 1024px) 100vw, 1024px\" data-was-processed=\"true\" /></figure>\r\n<p>Bạn c&oacute; thể đang tự hỏi&hellip;</p>\r\n<h5>Sự kh&aacute;c biệt giữa Dynamo Studio v&agrave; Dynamo Sandbox l&agrave; g&igrave; v&agrave; c&aacute;i n&agrave;o ph&ugrave; hợp với m&igrave;nh hơn?<br />Hai chuy&ecirc;n gia Dynamo Zach Kron v&agrave; Sol Amour c&oacute; những m&ocirc; tả ngắn gọn nhất về từng sản phẩm v&agrave; đối tượng ch&uacute;ng hướng đến:</h5>\r\n<h2>Dynamo Studio</h2>\r\n<h4>N&oacute; l&agrave; g&igrave;?</h4>\r\n<div class=\"td-g-rec td-g-rec-id-content_inline td_uid_11_611a530644b64_rand td_block_template_9 \">&nbsp;</div>\r\n<p>Dynamo Studio l&agrave; c&ocirc;ng nghệ cốt l&otilde;i với c&aacute;c c&ocirc;ng cụ h&igrave;nh học của Autodesk v&agrave; quyền truy cập v&agrave;o c&aacute;c dịch vụ đ&aacute;m m&acirc;y m&agrave; kh&ocirc;ng cần bất kỳ điều kiện ti&ecirc;n quyết n&agrave;o kh&aacute;c về phần mềm.</p>\r\n<h4>N&oacute; d&agrave;nh cho ai?</h4>\r\n<p>Đối với c&aacute;c bạn trong ng&agrave;nh gi&aacute;o dục, ch&uacute;ng t&ocirc;i hy vọng đ&acirc;y c&oacute; thể trở th&agrave;nh một c&ocirc;ng cụ giảng dạy c&oacute; thể tiếp cận rộng r&atilde;i hơn. Đối với những người l&agrave;m văn ph&ograve;ng, ch&uacute;ng t&ocirc;i hy vọng đ&acirc;y c&oacute; thể l&agrave; cầu nối giữa những người kh&ocirc;ng sử dụng Revit v&agrave; c&aacute;c dự &aacute;n dựa tr&ecirc;n Revit. Ch&uacute;ng t&ocirc;i hy vọng điều n&agrave;y cho ph&eacute;p bạn l&agrave;m việc tr&ecirc;n c&aacute;c bản ph&aacute;c thảo Dynamo tr&ecirc;n t&agrave;u điện ngầm hoặc n&oacute;i chuyện với c&aacute;c nh&agrave; tư vấn v&agrave; cộng t&aacute;c vi&ecirc;n tr&ecirc;n c&aacute;c nền tảng kh&aacute;c như Navis v&agrave; Rhino, đồng thời mở ra khả năng t&iacute;nh to&aacute;n cho người d&ugrave;ng ngo&agrave;i BIM truyền thống.</p>\r\n<h2>Dynamo Sandbox</h2>\r\n<h4>N&oacute; l&agrave; g&igrave;?</h4>\r\n<p>DynamoSandbox.exe l&agrave; c&ocirc;ng nghệ cốt l&otilde;i Dynamo miễn ph&iacute; (ng&ocirc;n ngữ kịch bản, sơ đồ n&uacute;t, c&ocirc;ng cụ thực thi) c&oacute; thể sử dụng một số c&ocirc;ng cụ h&igrave;nh học c&oacute; sẵn trong Revit v&agrave; kh&ocirc;ng c&oacute; khả năng đăng nhập v&agrave;o c&aacute;c dịch vụ đ&aacute;m m&acirc;y.</p>','<h4>N&oacute; d&agrave;nh cho ai?</h4>\r\n<p>Dynamo Sandbox d&agrave;nh cho c&aacute;c nh&agrave; ph&aacute;t triển g&oacute;i v&agrave; những người kh&aacute;c l&agrave;m việc với m&atilde; Dynamo, những người muốn lu&ocirc;n cập nhật những thứ mới nhất v&agrave; tuyệt vời nhất sắp ra mắt. Sandbox c&oacute; thể được sử dụng l&agrave;m giao diện lập tr&igrave;nh hoặc điều phối chung cho c&aacute;c chương tr&igrave;nh kh&aacute;c v&igrave; n&oacute; c&oacute; thể chạy m&agrave; kh&ocirc;ng cần c&agrave;i đặt bất kỳ chương tr&igrave;nh Autodesk n&agrave;o kh&aacute;c. L&agrave; một Tr&igrave;nh quản l&yacute; BIM, bạn c&oacute; thể kiểm tra c&aacute;c g&oacute;i kh&ocirc;ng cụ thể của m&aacute;y chủ lưu trữ trong một m&ocirc;i trường an to&agrave;n trước khi triển khai.</p>\r\n<p>Cuối c&ugrave;ng, t&ocirc;i chỉ khuy&ecirc;n bạn n&ecirc;n sử dụng Dynamo Sandbox cho Người quản l&yacute; BIM, nh&agrave; ph&aacute;t triển g&oacute;i hoặc người d&ugrave;ng th&agrave;nh thạo đ&atilde; quen thuộc với Dynamo. Bạn c&oacute; thể t&igrave;m thấy c&aacute;c bản dựng mới nhất cho Dynamo Sandbox, bao gồm c&aacute;c bản dựng h&agrave;ng ng&agrave;y tại DynamoBuilds.com.</p>\r\n<p>Đối với những người d&ugrave;ng kh&aacute;c muốn truy cập v&agrave;o giao diện lập tr&igrave;nh trực quan của Dynamo nhưng kh&ocirc;ng cần truy cập v&agrave;o c&aacute;c đối tượng Revit th&ocirc;ng qua API Revit, th&igrave; Dynamo Studio l&agrave; lựa chọn tốt nhất. Như đ&atilde; đề cập ở tr&ecirc;n, Dynamo Studio ổn định v&agrave; c&oacute; quyền truy cập v&agrave;o c&aacute;c dịch vụ đ&aacute;m m&acirc;y, điều n&agrave;y gi&uacute;p n&oacute; c&oacute; mặt tr&ecirc;n Sandbox. Dynamo Studio c&oacute; thể chạy tr&ecirc;n những nền tảng m&agrave; Revit kh&ocirc;ng thể chạy dễ d&agrave;ng, chẳng hạn như ultrabook hoặc m&aacute;y t&iacute;nh bảng chạy Windows 10; mở rộng những nơi bạn c&oacute; thể l&agrave;m việc hiệu quả.</p>','Thẻ Meta Title [vi]','Cannonical Link [vi]','Người dùng thường lăn tăn về Dynamo kiểu như: họ thường quen thuộc với Revit và đang tìm kiếm các cách cao cấp & tinh vi hơn để kiểm soát việc tạo, sắp xếp hoặc phân tích các đối tượng BIM trong một dự án. Dynamo vô đối, ban đầu được phát triển như một công cụ lập trình trực quan cho Revit.','Thẻ Meta Keyword [vi]',NULL),(13,10,'en','Types of modules in Grasshopper','Grasshopper uses an extremely diverse system of modules that can be linked together to create a “Clear History” for the model. There are 3 main types of modules:\r\n\r\n          Parameters contain data (values).\r\n          Component structure blocks.\r\n          Utility utilities and other special tools, called special.','<p>Parameter</p>\r\n<p>The tabs of Parameter are arranged in groups with similar functions. At the top is the Params card. Here, you can define basic geometry properties and input parameters such as data types for values, text for object names, etc. In particular, it contains sliders and panels. These are two extremely useful tools to support every process of the project.</p>\r\n<p>Define a Parameter</p>\r\n<p>When a parameter is placed on the canvas, it is just an empty parameter, showing orange. Now, we can define one or more geometric properties as well as basic parameters for it. To better understand how to define one or more geometry objects, right-click the parameter and use the desired options.</p>\r\n<p><br />To define the parameter, we choose Select one or Multiple depending on the number of objects you want to define. Then go to Rhino to select the object. As the above example is &ldquo;Set one Circle&rdquo; or &ldquo;Set Mutiple Circle&rdquo;.</p>\r\n<p><br />Parameter defined in Rhino or Grasshopper</p>\r\n<p>Geometric properties can be defined in both Grasshopper and Rhino. A circle sometimes needs to be defined in Grasshopper because defining it in Rhino and Grasshopper is different. This difference depends on which Parameter parameter needs to be defined. For example, a point can be defined both in Rhino and Grasshopper. This difference will indicate the possibility of changing the geometry in Rhino and Grasshopper later on. While this may seem trivial, it has a huge impact on the design process and your ability to effectively reshape your design. If the content of the Parameter parameter is defined in Grasshopper, the geometry customizations in Rhino will be removed. Conversely, if the content of the Parameter parameter is based on a geometry property in Rhino, then any change in Rhino will result in a change of the entire geometry property in Grasshopper.</p>','<p>Parameter</p>\r\n<p>The tabs of Parameter are arranged in groups with similar functions. At the top is the &nbsp; Params card. Here, you can define basic geometry properties and input parameters such as data types for values, text for object names, etc. In particular, it contains sliders and panels. These are two extremely useful tools to support every process of the project.</p>\r\n<p>Define a Parameter</p>\r\n<p>When a parameter is placed on the canvas, it is just an empty parameter, showing orange. Now, we can define one or more geometric properties as well as basic parameters for it. To better understand how to define one or more geometry objects, right-click the parameter and use the desired options.</p>\r\n<p>To define the parameter, we choose Select one or Multiple depending on the number of objects you want to define. Then go to Rhino to select the object. As the above example is &ldquo;Set one Circle&rdquo; or &ldquo;Set Mutiple Circle&rdquo;.</p>\r\n<p>Parameter defined in Rhino or Grasshopper</p>\r\n<p>Geometric properties can be defined in both Grasshopper and Rhino. A circle sometimes needs to be defined in Grasshopper because defining it in Rhino and Grasshopper is different. This difference depends on which Parameter parameter needs to be defined. For example, a point can be defined both in Rhino and Grasshopper. This difference will indicate the possibility of changing the geometry in Rhino and Grasshopper later on. While this may seem trivial, it has a huge impact on the design process and your ability to effectively reshape your design. If the content of the Parameter parameter is defined in Grasshopper, the geometry customizations in Rhino will be removed. Conversely, if the content of the Parameter parameter is based on a geometry property in Rhino, then any change in Rhino will result in a change of the entire geometry property in Grasshopper.</p>','Thẻ Meta Title [en]','Cannonical Link [en]','Grasshopper uses an extremely diverse system of modules that can be linked together to create a “Clear History” for the model. There are 3 main types of modules:\r\n\r\n          Parameters contain data (values).\r\n          Component structure blocks.\r\n          Utility utilities and other special tools, called special.','Thẻ Meta Keyword [en]',NULL),(14,10,'vi','Các loại module trong Grasshopper','Grasshopper sử dựng một hệ thống các mô-đun vô cùng đa dạng mà có thể kết nối với nhau để tạo ra một “Lịch sử rõ ràng” cho mô hình. Có 3 loại mô-đun chính :\r\n\r\n         Các Parameter chứa dữ liệu (giá trị).\r\n         Các khối cấu trúc Component.\r\n         Các  tiện ích utility và công cụ đặc biệt khác, gọi là special.','<p>Khi bạn thiết kế với Grasshopper, bạn sẽ d&ugrave;ng đến c&aacute;c m&ocirc;-đun n&agrave;y để tạo ra c&aacute;c đối tượng h&igrave;nh học. C&aacute;c m&ocirc;-đun c&oacute; phạm vị tương t&aacute;c rất rộng, ch&uacute;ng c&oacute; thể li&ecirc;n kết với nhau theo nhiều c&aacute;ch. Trong thư viện c&aacute;c m&ocirc;-đun, người d&ugrave;ng c&oacute; thể lựa chọn v&agrave; sử dụng m&ocirc;-đun m&agrave; cho ph&eacute;p họ định nghĩa được c&aacute;c dữ liệu đầu v&agrave;o m&agrave; m&igrave;nh cần. Điều n&agrave;y cho ph&eacute;p bạn c&oacute; thể điều khiển được kết quả cuối c&ugrave;ng cho định nghĩa của m&igrave;nh để tạo ra c&aacute;c đối tượng h&igrave;nh học như mong muốn.</p>\r\n<p><img class=\"wp-image-7129 aligncenter lazyloaded\" src=\"http://vietnambim.net/wp-content/uploads/2018/06/20170531124631-300x165.jpeg\" srcset=\"https://vietnambim.net/wp-content/uploads/2018/06/20170531124631-300x165.jpeg 300w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124631.jpeg 350w\" alt=\"\" width=\"413\" height=\"227\" data-lazy-src=\"http://vietnambim.net/wp-content/uploads/2018/06/20170531124631-300x165.jpeg\" data-lazy-srcset=\"https://vietnambim.net/wp-content/uploads/2018/06/20170531124631-300x165.jpeg 300w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124631.jpeg 350w\" data-lazy-sizes=\"(max-width: 413px) 100vw, 413px\" data-was-processed=\"true\" /></p>\r\n<div class=\"td-g-rec td-g-rec-id-content_inline td_uid_11_611a5419b5571_rand td_block_template_9 \">&nbsp;</div>\r\n<p>Để x&acirc;y dựng một h&ecirc; thống c&aacute;c đối tượng h&igrave;nh học phức tạp, bạn cần thực hiện từng bước một. Nghĩa l&agrave;, khi bạn bắt đầu một dự &aacute;n với Grasshopper, điều đầu ti&ecirc;n l&agrave; cần phải ph&acirc;n t&iacute;ch l&agrave;m c&aacute;ch n&agrave;o để tạo dựng n&ecirc;n c&aacute;c đối tượng h&igrave;nh học đ&oacute;. Cần thực hiện những bước g&igrave;. Trong Rhino, để vẽ một đường cong, bạn d&ugrave;ng chuột. Hoặc c&aacute;c thiết lập cho đường cong đ&oacute; c&oacute; thể được thay đổi ở d&ograve;ng command line. Trong Grasshopper, bạn kh&ocirc;ng l&agrave;m vậy. Bạn sẽ định nghĩa từng bước cho qu&aacute; tr&igrave;nh tạo dựng đường cong đ&oacute; với sự trợ gi&uacute;p của chuột. Nhưng, đường cong n&agrave;y thay v&igrave; bạn phải click c&ocirc;ng cụ vẽ đường cong v&agrave; thực hiện vẽ bằng c&aacute;ch truyền thống th&igrave; với Grasshopper, bạn sẽ định nghĩa c&aacute;c điểm point v&agrave; đường cong sẽ được tọa ra th&ocirc;ng qua c&aacute;c điểm point n&agrave;y. Từ đ&oacute; về sau, bạn sẽ dễ d&agrave;ng thay đổi h&igrave;nh dạng đường cong theo mong muốn bằng c&aacute;ch thay đổi c&aacute;c điểm point n&agrave;y. Ở v&iacute; dụ dưới, việc n&agrave;y được hỗ trợ bởi c&aacute;c thanh trượt slider.</p>','<p><strong>Parameter</strong></p>\r\n<p>C&aacute;c tab của Parameter được bố tr&iacute; theo từng nh&oacute;m với chức năng tương đồng. Đứng đầu l&agrave;&nbsp;&nbsp;thẻ Params. Ở đ&acirc;y, bạn c&oacute; thể định nghĩa c&aacute;c thuộc t&iacute;nh h&igrave;nh học v&agrave; th&ocirc;ng số đầu v&agrave;o cơ bản như kiểu dữ liệu cho c&aacute;c trị số, c&aacute;c text cho t&ecirc;n đối tượng,&hellip;Đặc biệt, n&oacute; chứa slider v&agrave; panel. Đ&acirc;y l&agrave; 2 c&ocirc;ng cụ v&ocirc; c&ugrave;ng hữu dụng để hỗ trợ cho mọi tiến tr&igrave;nh của dự &aacute;n.</p>\r\n<p><strong><em>Định nghĩa một Parameter</em></strong></p>\r\n<p>Khi một parameter được đặt v&agrave;o nền canvas th&igrave; l&uacute;c n&agrave;y chỉ l&agrave; một parameter trống, hiện m&agrave;u cam. B&acirc;y giờ, ta c&oacute; thể định nghĩa một hoặc nhiều thuộc t&iacute;nh h&igrave;nh học cũng như c&aacute;c th&ocirc;ng số cơ bản cho n&oacute;. Để hiểu r&otilde; hơn về c&aacute;ch định nghĩa một hoặc nhiều đối tượng h&igrave;nh học, ta chuột phải v&agrave;o parameter v&agrave; sử dụng c&aacute;c t&ugrave;y chọn mong muốn.</p>\r\n<p><img class=\"alignnone wp-image-7135 lazyloaded\" src=\"http://vietnambim.net/wp-content/uploads/2018/06/20170531124814-300x296.jpeg\" srcset=\"https://vietnambim.net/wp-content/uploads/2018/06/20170531124814-300x296.jpeg 300w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124814-426x420.jpeg 426w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124814.jpeg 540w\" alt=\"\" width=\"463\" height=\"457\" data-lazy-src=\"http://vietnambim.net/wp-content/uploads/2018/06/20170531124814-300x296.jpeg\" data-lazy-srcset=\"https://vietnambim.net/wp-content/uploads/2018/06/20170531124814-300x296.jpeg 300w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124814-426x420.jpeg 426w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124814.jpeg 540w\" data-lazy-sizes=\"(max-width: 463px) 100vw, 463px\" data-was-processed=\"true\" /></p>\r\n<p>Để định nghĩa cho parameter, ta chọn Select one hoặc Multiple phụ thuộc v&agrave;o số lượng đối tượng m&agrave; bạn muốn định nghĩa. Sau đ&oacute;, qua Rhino để chọn v&agrave;o đối tượng. Như v&iacute; dụ tr&ecirc;n l&agrave; &ldquo; Set one Circle&rdquo; hoặc &rdquo;Set Mutiple Circle&rdquo;.</p>\r\n<p><img class=\"alignnone wp-image-7133 lazyloaded\" src=\"http://vietnambim.net/wp-content/uploads/2018/06/20170531124856-300x293.jpeg\" srcset=\"https://vietnambim.net/wp-content/uploads/2018/06/20170531124856-300x293.jpeg 300w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124856-430x420.jpeg 430w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124856.jpeg 450w\" alt=\"\" width=\"523\" height=\"511\" data-lazy-src=\"http://vietnambim.net/wp-content/uploads/2018/06/20170531124856-300x293.jpeg\" data-lazy-srcset=\"https://vietnambim.net/wp-content/uploads/2018/06/20170531124856-300x293.jpeg 300w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124856-430x420.jpeg 430w, https://vietnambim.net/wp-content/uploads/2018/06/20170531124856.jpeg 450w\" data-lazy-sizes=\"(max-width: 523px) 100vw, 523px\" data-was-processed=\"true\" /></p>\r\n<p><strong><em>Parameter được định nghĩa trong Rhino hay Grasshopper</em></strong></p>\r\n<p>C&aacute;c thuộc t&iacute;nh h&igrave;nh học c&oacute; thể được định nghĩa cả trong Grasshopper lẫn Rhino. Một đường tr&ograve;n đ&ocirc;i l&uacute;c cần được định nghĩa trong Grasshopper v&igrave; khi định nghĩa n&oacute; ở Rhino v&agrave; Grasshopper c&oacute; sự kh&aacute;c biệt. Sự sai kh&aacute;c n&agrave;y phụ thuộc v&agrave;o tham số Parameter n&agrave;o cần định nghĩa. V&iacute; dụ, một điểm point c&oacute; thể được định nghĩa cả trong Rhino v&agrave; Grasshopper. Sự kh&aacute;c biệt n&agrave;y sẽ chỉ ra khả năng thay đổi h&igrave;nh học trong Rhino v&agrave; Grasshopper sau n&agrave;y. Mặc d&ugrave; điều n&agrave;y c&oacute; vẻ tầm thường, nhưng n&oacute; c&oacute; ảnh hưởng rất lớn đến qu&aacute; tr&igrave;nh thiết kế v&agrave; khả năng thay đổi h&igrave;nh dạng thiết kế của bạn một c&aacute;ch hiệu quả. Nếu nội dung của tham số Parameter được định nghĩa trong Grasshopper, c&aacute;c t&ugrave;y chỉnh h&igrave;nh học trong Rhino sẽ kh&ocirc;ng c&ograve;n. Ngược lại, nếu nội dung của tham số Parameter dựa tr&ecirc;n thuộc t&iacute;nh h&igrave;nh học trong Rhino, th&igrave; mọi thay đổi trong Rhino sẽ dẫn đến việc thay đổi to&agrave;n bộ thuộc t&iacute;nh h&igrave;nh học trong Grasshopper.</p>','Thẻ Meta Title [vi]','Cannonical Link [vi]','Grasshopper sử dựng một hệ thống các mô-đun vô cùng đa dạng mà có thể kết nối với nhau để tạo ra một “Lịch sử rõ ràng” cho mô hình. Có 3 loại mô-đun chính :\r\n\r\n         Các Parameter chứa dữ liệu (giá trị).\r\n         Các khối cấu trúc Component.\r\n         Các  tiện ích utility và công cụ đặc biệt khác, gọi là special.','Thẻ Meta Keyword [vi]',NULL);
/*!40000 ALTER TABLE `products_translations` ENABLE KEYS */;
UNLOCK TABLES;

