INSERT INTO `project_categories_translations` VALUES (1,1,'en','BIM 3D Coordination','3D BIM is perhaps the BIM we are most familiar with - the process of creating graphical and non-graphical information and sharing this information in a Common Data Environment (CDE).',NULL),(2,1,'vi','Phối hợp BIM 3D','3D BIM is perhaps the BIM we are most familiar with - the process of creating graphical and non-graphical information and sharing this information in a Common Data Environment (CDE).',NULL),(3,2,'en','BIM 4D','4D BIM adds an extra dimension of information to a project information model in the form of scheduling data. This data is added to components which will build in detail as the project progresses. This information can be used to obtain accurate programme information and visualisations showing how your project will develop sequentially.',NULL),(4,2,'vi','BIM 4D','4D BIM adds an extra dimension of information to a project information model in the form of scheduling data. This data is added to components which will build in detail as the project progresses. This information can be used to obtain accurate programme information and visualisations showing how your project will develop sequentially.',NULL),(5,3,'en','BIM 5D','Drawing on the components of the information model',NULL),(6,3,'vi','BIM 5D','Drawing on the components of the information model',NULL),(7,4,'en','Project was implemented','Tích hợp là cốt lõi của dự án – Nó linh hoạt, không gian mở cung cấp cho hơn 700 học sinh một môi trường giáo dục được thiết kế để khuyến khích sự hợp tác và học tập.',NULL),(8,4,'vi','Các dự án đã thực hiện','Tích hợp là cốt lõi của dự án – Nó linh hoạt, không gian mở cung cấp cho hơn 700 học sinh một môi trường giáo dục được thiết kế để khuyến khích sự hợp tác và học tập.',NULL);
