INSERT INTO `settings_translations` VALUES (1,1,'en',NULL,NULL,NULL,NULL,'BIM (Building Information Modeling)','Tổng Quan Về Phần Mềm BIM','BIM (Building Information Modeling) is an advanced construction industry (AEC) process based on digital 3D models used throughout the lifecycle of a design, infrastructure and construction project. .','Centralized data management','With BIM, everything happens automatically and accurately, you just need to focus on the quality of the 3D design models.','Intuitive model design','The investor will easily get the most intuitive view of the project, the structural design team, MEP... easily detect conflicts, optimally design the details in the space of the building.','Save cost - time',NULL,NULL,NULL,'Sản Phẩm / Dịch Vụ','Tất Cả Sản Phẩm / Dịch Vụ Của Chúng Tôi','Tin Tức','Đừng Bỏ Lỡ Những Tin Tức Mới Nhất','Đối tác','Chúng Tôi Tự Hào Khi Có Sự Tham Gia Của Các Đối Tác','Liên hệ','Vui Lòng Cung Cấp Thông Tin. Chúng Tôi Sẽ Liên Hệ Với Bạn.','Vietnam BIM Network was born to create consensus in the BIM practitioner community on working methods, formats, and cultures. Building a common data exchange and information exchange environment about BIM in Vietnam oriented towards Connection - Sharing - Extensive cooperation. use footer','BIM Company','Vietnam BIM Network được sinh ra để tạo nên sự đồng thuận trong cộng đồng người hành nghề BIM về phương pháp, định dạng, văn hóa làm việc. Xây dựng một môi trường trao đổi dữ liệu, trao đổi t','Studio 76d, Riley Ford, North Michaelchester, CF99 6QQ','(+091) 413 554 8598','(+091) 413 554 8599',NULL),(2,1,'vi',NULL,NULL,NULL,NULL,'BIM (Building Information Modeling)','Tổng Quan Về Phần Mềm BIM','BIM (Building Information Modeling) là một quy trình tiên tiến được ứng dụng trong ngành xây dựng (AEC) dựa trên các mô hình 3D kỹ thuật số được sử dụng xuyên suốt vòng đời của một dự án thiết kế, hạ tầng và xây dựng.','Quản lý dữ liệu tập trung','Với BIM, mọi thứ sẽ diễn ra một cách tự động và chính xác, bạn chỉ cần tập trung vào chất lượng của các mô hình thiết kế 3D.','Thiết kế mô hình trực quan','Chủ đầu tư sẽ dễ dàng có được một cái nhìn trực quan nhất về dự án, đội ngũ thiết kế kết cấu, MEP... dễ dàng phát hiện các xung đột, thiết kế tối ưu các chi tiết trong không gian của tòa nhà','Tiết kiệm chi phí - thời gian','Giảm thiểu các khoảng phát sinh về chi phí lẫn thời gian làm việc với việc quản lý dữ liệu đồng nhất, tránh mất mác trong quá trình lưu trữ và quản lý tài liệu.','Tăng khả năng cộng tác','BIM giúp sự liên kết giữa các phòng ban trở nên chặt chẽ hơn, từ thiết kế kiến trúc, kết cấu, MEP, dự toán... tất cả đều làm việc trên một mô hình thống nhất','Sản Phẩm / Dịch Vụ','Tất Cả Sản Phẩm / Dịch Vụ Của Chúng Tôi','Tin Tức','Đừng Bỏ Lỡ Những Tin Tức Mới Nhất','Đối tác','Chúng Tôi Tự Hào Khi Có Sự Tham Gia Của Các Đối Tác','Liên hệ','Vui Lòng Cung Cấp Thông Tin. Chúng Tôi Sẽ Liên Hệ Với Bạn.','Vietnam BIM Network được sinh ra để tạo nên sự đồng thuận trong cộng đồng người hành nghề BIM về phương pháp, định dạng, văn hóa làm việc. Xây dựng một môi trường trao đổi dữ liệu, trao đổi thông tin chung về BIM ở Việt Nam định hướng tới sự Kết nối – Chia sẻ - Hợp tác sâu rộng. dung footer','BIM Company','Vietnam BIM Network được sinh ra để tạo nên sự đồng thuận trong cộng đồng người hành nghề BIM về phương pháp, định dạng, văn hóa làm việc. Xây dựng một môi trường trao đổi dữ liệu, trao đổi t','Studio 76d, Riley Ford, North Michaelchester, CF99 6QQ','(+091) 413 554 8598','(+091) 413 554 8599',NULL);
